import { ASSET, HEROES, RACES, JOBS, REGIONS, ENEMIES, SKILLS, EQUIPMENT, EQUIP_MAP, QUESTS, CORE_SKILLS, BASE_SKILLS, RARITY_ORDER, findJob, getSkill, findEnemy, findRegion } from './data.js';

const SAVE_KEY='omnil_concord_rpg_save_v3';
const LEGACY_SAVE_KEY='omnil_concord_rpg_save_v2';
const VERSION='2.0.0';
const MAX_INVENTORY=10000;
const INVENTORY_PAGE_SIZE=50;
const $=s=>document.querySelector(s);
const $$=s=>[...document.querySelectorAll(s)];
const clamp=(n,a,b)=>Math.max(a,Math.min(b,n));
const rand=(a,b)=>Math.floor(Math.random()*(b-a+1))+a;
const pick=a=>a[Math.floor(Math.random()*a.length)];
const deep=v=>JSON.parse(JSON.stringify(v));
const fmt=n=>Math.floor(n||0).toLocaleString('ja-JP');
const pct=(n,d)=>`${Math.round((n/d)*100)}%`;

let state;
let loopTimer=null;
let battleTimer=null;
let audioUnlocked=false;
let currentBgm=null;
const bgm={};
const sfx={};
const audioFiles={home:'bgm_home.wav',field:'bgm_field.wav',battle:'bgm_battle.wav',boss:'bgm_boss.wav'};
const sfxFiles={click:'se_click.wav',cancel:'se_cancel.wav',hit:'se_hit.wav',magic:'se_magic.wav',heal:'se_heal.wav',shield:'se_shield.wav',rare:'se_rare.wav',level:'se_level.wav',unlock:'se_unlock.wav',defeat:'se_defeat.wav',victory:'se_victory.wav'};

let uidCounter=0;
function makeItem(id,upgrade=0,locked=false){const uid=(globalThis.crypto?.randomUUID?.()||`i_${Date.now().toString(36)}_${(++uidCounter).toString(36)}_${Math.random().toString(36).slice(2,9)}`);return {uid,id,upgrade,locked:!!locked,favorite:false,junk:false,acquiredAt:Date.now()};}
function starterBy(type,affix='guard',rarity='コモン'){return EQUIPMENT.find(x=>x.type===type&&x.affix===affix&&x.rarity===rarity)||EQUIPMENT.find(x=>x.type===type);}
function defaultState(){
 const starterItems=[];
 const equip={};
 const add=(hero,type,affix)=>{const e=starterBy(type,affix); const item=makeItem(e.id); starterItems.push(item); equip[hero]??={}; equip[hero][type]=item.uid;};
 add('kozen','onehand_sword','crit');add('kozen','light_armor','evasion');add('kozen','ring','crit');add('kozen','charm','guard');
 add('hakurei','shield','guard');add('hakurei','heavy_armor','guard');add('hakurei','staff','magic');add('hakurei','necklace','guard');
 add('kokurei','dagger','crit');add('kokurei','light_armor','evasion');add('kokurei','bracelet','crit');add('kokurei','charm','status');
 const h={};
 HEROES.forEach(x=>h[x.id]={id:x.id,baseSkill:x.baseSkill,level:1,xp:0,bond:1,race:x.defaultRace,job:x.defaultJob,jobXp:{[x.defaultJob]:0},skills:x.defaultSkills.map(k=>CORE_SKILLS[k]),equip:equip[x.id]||{}});
 return {
  version:VERSION,screen:'title',ui:{selectedHero:'kozen',selectedRegion:'verdant_steppe',inventoryFilter:'',inventoryType:'all',inventoryRarity:'all',inventoryTag:'all',inventoryMinLevel:0,inventoryMaxLevel:0,inventorySort:'newest',inventoryPage:0,inventorySelected:[],bulkExcludeEquipped:true,bulkExcludeLocked:true,bulkExcludeFavorite:true,bulkExcludeUnique:true,skillsFilter:'',skillsTag:'all',skillsPage:0,codexPage:0,modalSkillsPage:0,modalSkillSlot:0},
  meta:{gold:240,crystals:18,shards:30,materials:{草原の繊維:12,鉄片:8,光の粉:4},kills:0,status:0,barrier:0,forge:0,bosses:0},
  heroes:h,inventory:starterItems,
  unlocks:{regions:['verdant_steppe'],races:['human','high_elf','dark_elf'],jobs:['warrior','swordsman','guardian','rogue','priest','black_mage'],skills:Object.values(CORE_SKILLS),story:0,bosses:{},quests:[],achievements:[]},
  battle:null,
  loop:{running:false,regionId:'verdant_steppe',boss:false,target:10,unlimited:false,run:0,wins:0,deaths:0,gold:0,xp:0,drops:[],logs:[],stopRare:false,stopDeath:true,stopFull:true,stopHp:0,stopMp:0,stopItem:'',stopMaterial:'',stopMaterialCount:0,stopXp:0,session:0,autoRules:{'コモン':'sell','アンコモン':'keep','レア':'keep','エピック':'keep','レジェンダリー':'keep','ユニーク':'keep'},keepTypes:[],keepTags:[],keepAffixes:[],keepMinLevel:0,preFullMode:'process',autoKept:0,autoSold:0,autoBroken:0,autoGold:0,autoMaterials:0,lastStopReason:''},
  settings:{bgm:true,se:true,bgmVol:0.36,seVol:0.55},flags:{seenTitle:false},lastSaved:0
 };
}
function normalizeState(parsed){
 const base=defaultState();
 if(!parsed||typeof parsed!=='object'||!parsed.heroes||!parsed.meta)throw Error('invalid');
 const safe={...base,...parsed,
  ui:{...base.ui,...(parsed.ui||{})},
  settings:{...base.settings,...(parsed.settings||{})},
  flags:{...base.flags,...(parsed.flags||{})},
  unlocks:{...base.unlocks,...(parsed.unlocks||{})},
  loop:{...base.loop,...(parsed.loop||{})},
  heroes:{...base.heroes},
  meta:{...base.meta,...(parsed.meta||{}),materials:{...base.meta.materials,...((parsed.meta?.materials&&typeof parsed.meta.materials==='object')?parsed.meta.materials:{})}},
 };
 safe.inventory=Array.isArray(parsed.inventory)?parsed.inventory.filter(i=>i&&typeof i.uid==='string'&&EQUIP_MAP[i.id]).slice(0,MAX_INVENTORY).map(i=>({uid:i.uid,id:i.id,upgrade:clamp(Number(i.upgrade)||0,0,10),locked:!!i.locked,favorite:!!i.favorite,junk:!!i.junk,acquiredAt:Number(i.acquiredAt)||0})):base.inventory;
 safe.ui.inventorySelected=Array.isArray(safe.ui.inventorySelected)?[...new Set(safe.ui.inventorySelected.filter(uid=>safe.inventory.some(i=>i.uid===uid)))].slice(0,MAX_INVENTORY):[];
 safe.ui.inventoryPage=clamp(Number(safe.ui.inventoryPage)||0,0,9999);
 safe.ui.inventoryMinLevel=Math.max(0,Number(safe.ui.inventoryMinLevel)||0); safe.ui.inventoryMaxLevel=Math.max(0,Number(safe.ui.inventoryMaxLevel)||0);
 safe.loop.autoRules={...base.loop.autoRules,...((safe.loop.autoRules&&typeof safe.loop.autoRules==='object')?safe.loop.autoRules:{})};
 for(const r of RARITY_ORDER) if(!['keep','sell','break'].includes(safe.loop.autoRules[r])) safe.loop.autoRules[r]='keep';
 safe.loop.keepTypes=Array.isArray(safe.loop.keepTypes)?safe.loop.keepTypes.filter(Boolean):[];
 safe.loop.keepTags=Array.isArray(safe.loop.keepTags)?safe.loop.keepTags.filter(Boolean):[];
 safe.loop.keepAffixes=Array.isArray(safe.loop.keepAffixes)?safe.loop.keepAffixes.filter(Boolean):[];
 safe.loop.keepMinLevel=Math.max(0,Number(safe.loop.keepMinLevel)||0);
 safe.loop.autoKept=Number(safe.loop.autoKept)||0; safe.loop.autoSold=Number(safe.loop.autoSold)||0; safe.loop.autoBroken=Number(safe.loop.autoBroken)||0; safe.loop.autoGold=Number(safe.loop.autoGold)||0; safe.loop.autoMaterials=Number(safe.loop.autoMaterials)||0;
 safe.unlocks.regions=Array.isArray(safe.unlocks.regions)?safe.unlocks.regions.filter(id=>findRegion(id)).filter((v,i,a)=>a.indexOf(v)===i):base.unlocks.regions;
 safe.unlocks.races=Array.isArray(safe.unlocks.races)?safe.unlocks.races.filter(id=>raceDef(id)).filter((v,i,a)=>a.indexOf(v)===i):base.unlocks.races;
 safe.unlocks.jobs=Array.isArray(safe.unlocks.jobs)?safe.unlocks.jobs.filter(id=>findJob(id)).filter((v,i,a)=>a.indexOf(v)===i):base.unlocks.jobs;
 safe.unlocks.skills=Array.isArray(safe.unlocks.skills)?safe.unlocks.skills.filter(id=>getSkill(id)?.id===id).filter((v,i,a)=>a.indexOf(v)===i):base.unlocks.skills;
 safe.unlocks.quests=Array.isArray(safe.unlocks.quests)?safe.unlocks.quests:[];
 safe.unlocks.achievements=Array.isArray(safe.unlocks.achievements)?safe.unlocks.achievements:[];
 safe.unlocks.bosses=(safe.unlocks.bosses&&typeof safe.unlocks.bosses==='object')?safe.unlocks.bosses:{};
 for(const hero of HEROES){
  const incoming=parsed.heroes?.[hero.id]||{};
  const fallback=base.heroes[hero.id];
  const h={...fallback,...incoming};
  h.id=hero.id;
  h.baseSkill=hero.baseSkill;
  h.race=raceDef(h.race)?h.race:fallback.race;
  h.job=findJob(h.job)?h.job:fallback.job;
  h.level=clamp(Number(h.level)||1,1,999);
  h.xp=Math.max(0,Number(h.xp)||0);
  h.bond=clamp(Number(h.bond)||1,1,99);
  h.jobXp=(h.jobXp&&typeof h.jobXp==='object')?h.jobXp:{[h.job]:0};
  h.skills=Array.isArray(h.skills)?h.skills.filter(id=>getSkill(id)?.id===id).slice(0,4):fallback.skills;
  while(h.skills.length<4)h.skills.push(fallback.skills[h.skills.length]||CORE_SKILLS.prism_edge);
  h.equip=(h.equip&&typeof h.equip==='object')?Object.fromEntries(Object.entries(h.equip).filter(([,uid])=>safe.inventory.some(i=>i.uid===uid))):{};
  safe.heroes??={}; safe.heroes[hero.id]=h;
 }
 if(!safe.ui.selectedHero||!safe.heroes[safe.ui.selectedHero])safe.ui.selectedHero='kozen';
 if(!findRegion(safe.ui.selectedRegion))safe.ui.selectedRegion='verdant_steppe';
 if(!findRegion(safe.loop.regionId))safe.loop.regionId='verdant_steppe';
 safe.loop.running=false; // Never resume an interval from a persisted browser session.
 safe.battle=null; // Return to a safe screen after refresh/import.
 if(!['title','home','explore','party','jobs','skills','inventory','forge','loop','codex','story','settings','battle'].includes(safe.screen))safe.screen='home';
 return safe;
}
function loadState(){
 try{const raw=localStorage.getItem(SAVE_KEY)||localStorage.getItem(LEGACY_SAVE_KEY);if(!raw)return defaultState();return normalizeState(JSON.parse(raw));}catch(e){return defaultState()}
}
function saveState(silent=true){state.lastSaved=Date.now();try{localStorage.setItem(SAVE_KEY,JSON.stringify(state));if(!silent)toast('セーブしました','good')}catch(e){toast('セーブに失敗しました。容量を確認してください。','warn')}}
function resetState(){clearTimers();state=defaultState();saveState();render();toast('新しい旅を始めます','good')}
function clearTimers(){if(loopTimer){clearInterval(loopTimer);loopTimer=null}if(battleTimer){clearInterval(battleTimer);battleTimer=null}}

function heroDef(id){return HEROES.find(x=>x.id===id)}
function raceDef(id){return RACES.find(x=>x.id===id)}
function invItem(uid){return state.inventory.find(i=>i.uid===uid)}
function itemDefFromUid(uid){const it=invItem(uid);return it?EQUIP_MAP[it.id]:null}
function heroItems(hero){return Object.values(hero.equip||{}).map(itemDefFromUid).filter(Boolean)}
function jobLevel(hero,jobId=hero.job){const xp=hero.jobXp?.[jobId]||0;return clamp(1,1+Math.floor(xp/120),10)}
function jobProgress(hero,jobId=hero.job){return (hero.jobXp?.[jobId]||0)%120}
function maxJobLevel(id){return Math.max(...Object.values(state.heroes).map(h=>jobLevel(h,id))) }
function skillKnown(id){return state.unlocks.skills.includes(id)}
function jobUnlocked(id){return state.unlocks.jobs.includes(id)}
function regionUnlocked(id){return state.unlocks.regions.includes(id)}
function raceUnlocked(id){return state.unlocks.races.includes(id)}
function isBossCleared(id){return !!state.unlocks.bosses[id]}
function baseSkillDef(heroId){return BASE_SKILLS[heroDef(heroId)?.baseSkill]}
function rarityRank(r){return Math.max(0,RARITY_ORDER.indexOf(r))}
function saleValue(inv){const d=EQUIP_MAP[inv.id];return Math.max(15,Math.floor((d.level*8+d.stars*28+(inv.upgrade||0)*18)*(1+rarityRank(d.rarity)*.16)))}
function isEquippedUid(uid){return Object.values(state.heroes).some(h=>Object.values(h.equip||{}).includes(uid))}
function itemFlags(inv){const d=EQUIP_MAP[inv.id];return {equipped:isEquippedUid(inv.uid),locked:!!inv.locked,favorite:!!inv.favorite,unique:d?.rarity==='ユニーク'} }
function isBulkEligible(inv){const f=itemFlags(inv),u=state.ui; return !(u.bulkExcludeEquipped&&f.equipped) && !(u.bulkExcludeLocked&&f.locked) && !(u.bulkExcludeFavorite&&f.favorite) && !(u.bulkExcludeUnique&&f.unique)}

function modsFromItems(items){const m={};items.forEach(it=>{if(!it)return;Object.entries(it.stats||{}).forEach(([k,v])=>m[k]=(m[k]||0)+v);});return m}
function getHeroStats(hero){
 const def=heroDef(hero.id), race=raceDef(hero.race), job=findJob(hero.job),lvl=jobLevel(hero); const instances=Object.values(hero.equip||{}).map(invItem).filter(Boolean);const items=instances.map(i=>EQUIP_MAP[i.id]).filter(Boolean); const im=modsFromItems(items); const out={...def.base};
 const add=src=>Object.entries(src||{}).forEach(([k,v])=>out[k]=(out[k]||0)+v);
 add(race.bonus); Object.entries(job.bonus).forEach(([k,v])=>out[k]=(out[k]||0)+v*lvl); add(im);
 instances.forEach(inv=>{const it=EQUIP_MAP[inv.id],up=inv.upgrade||0;if(up&&it){Object.keys(it.stats||{}).forEach(k=>out[k]=(out[k]||0)+Math.floor((it.stats[k]||0)*up*.08))}});
 out.hp=Math.round(out.hp+hero.level*14);out.mp=Math.round(out.mp+hero.level*5);out.atk=Math.round(out.atk+hero.level*2);out.mag=Math.round(out.mag+hero.level*2);out.def=Math.round(out.def+hero.level*1.4);out.res=Math.round(out.res+hero.level*1.3);out.spd=Math.round(out.spd);out.crit=Math.round(out.crit||0);out.evade=Math.round(out.evade||0);
 out.mods={barrier:im.barrier||0, lifesteal:im.lifesteal||0,statusPower:im.statusPower||0,dropRate:im.dropRate||0,xpRate:im.xpRate||0,prism:im.prism||0};
 return out;
}
function partyPower(){return Object.values(state.heroes).reduce((sum,h)=>{const s=getHeroStats(h);return sum+s.hp*.22+s.mp*.1+s.atk*2.3+s.mag*2.3+s.def*1.6+s.res*1.5+s.spd*.5+s.crit*1.8},0)}
function getAllHeroSkillIds(hero){const job=findJob(hero.job);const tag=job.tag;return SKILLS.filter(s=>skillKnown(s.id)|| (s.rank<=jobLevel(hero)/2 && (s.tags.includes('物理')||s.tags.includes('魔法')||s.tags.includes('回復')||s.tags.includes('防壁')))).map(s=>s.id)}

function initAudio(){if(audioUnlocked)return;audioUnlocked=true;Object.entries(audioFiles).forEach(([key,file])=>{const a=new Audio(`./assets/audio/${file}`);a.loop=true;a.preload='auto';bgm[key]=a});Object.entries(sfxFiles).forEach(([key,file])=>{const a=new Audio(`./assets/audio/${file}`);a.preload='auto';sfx[key]=a});setVolumes()}
function setVolumes(){Object.values(bgm).forEach(a=>a.volume=state.settings.bgm?state.settings.bgmVol:0);}
function playBgm(key){initAudio();if(!state.settings.bgm)return;const current=bgm[key];if(currentBgm===key&&current&&!current.paused)return;Object.entries(bgm).forEach(([k,a])=>{if(k!==key){a.pause();a.currentTime=0}});currentBgm=key;const a=bgm[key];if(a){a.volume=state.settings.bgmVol;a.play().catch(()=>{})}}
function playSfx(key){initAudio();if(!state.settings.se)return;const base=sfx[key];if(!base)return;const a=base.cloneNode();a.volume=state.settings.seVol;a.play().catch(()=>{})}

function toast(msg,type=''){const root=$('#toast-root');const e=document.createElement('div');e.className=`toast ${type}`;e.textContent=msg;root.append(e);setTimeout(()=>e.remove(),3100)}
function modal(title,body,{wide=false}={}){$('#modal-root').innerHTML=`<div class="modal-backdrop" data-act="modal-backdrop"><section class="modal ${wide?'wide':''}" role="dialog" aria-modal="true"><header class="modal-head"><h2>${title}</h2><button class="modal-close" data-act="close-modal" aria-label="閉じる">×</button></header><div class="modal-body">${body}</div></section></div>`}
function closeModal(){const r=$('#modal-root');if(r.innerHTML){r.innerHTML='';playSfx('cancel')}}
function confirmModal(title,text,act,btn='実行',kind='warn'){modal(title,`<div class="confirm"><p class="page-lead">${text}</p><div class="modal-actions"><button class="btn ${kind}" data-act="${act}">${btn}</button><button class="btn ghost" data-act="close-modal">キャンセル</button></div></div>`)}

function statText(s){return `HP ${fmt(s.hp)} / MP ${fmt(s.mp)} / 物攻 ${fmt(s.atk)} / 魔攻 ${fmt(s.mag)} / 防 ${fmt(s.def)} / 魔防 ${fmt(s.res)} / 速 ${fmt(s.spd)} / 会心 ${fmt(s.crit)}% / 回避 ${fmt(s.evade)}%`}
function tagHtml(tags=[]){return tags.map(t=>`<span class="tag ${t==='火'?'fire':t==='氷'?'ice':t==='雷'?'thunder':t==='虹'?'rainbow':''}">${t}</span>`).join('')}
function heroCard(hero,{selectable=false}={}){const d=heroDef(hero.id),s=getHeroStats(hero),j=findJob(hero.job),r=raceDef(hero.race),selected=state.ui.selectedHero===hero.id;return `<article class="card hero-card ${selected?'selected':''}" ${selectable?`data-act="select-hero" data-id="${hero.id}"`:''}><div class="hero-top"><img class="hero-sprite" src="${ASSET.hero(hero.id,'idle')}" alt="${d.name}"><div><div class="hero-name">${d.name} <small class="hero-ruby">${d.ruby}</small></div><div class="role">${j.name} Lv${jobLevel(hero)} ／ ${r.name}</div><div class="tiny muted">Lv${hero.level}　${d.role}</div></div></div><div class="hero-bars"><div class="barline"><span>HP</span><div class="bar hp"><i style="width:100%"></i></div><b>${fmt(s.hp)}</b></div><div class="barline"><span>MP</span><div class="bar mp"><i style="width:100%"></i></div><b>${fmt(s.mp)}</b></div></div><div class="tag-row">${tagHtml([j.tag,r.tag==='element'?'属性':r.tag==='loot'?'周回':r.tag==='shield'?'防壁':r.tag])}</div></article>`}
function topbar(){return `<header class="topbar"><div class="topbar-inner"><div class="brand"><i class="brand-mark"></i><div><div class="brand-title">全零〈オムニル〉</div><div class="brand-sub">白黒虹の継承者　v${VERSION}</div></div></div><div class="header-stats"><span class="stat-pill">G <b>${fmt(state.meta.gold)}</b></span><span class="stat-pill">晶片 <b>${fmt(state.meta.crystals)}</b></span><span class="stat-pill">魂片 <b>${fmt(state.meta.shards)}</b></span><span class="stat-pill">総合戦力 <b>${fmt(partyPower())}</b></span></div><button class="btn ghost tiny-btn mobile-menu" data-act="toggle-nav">メニュー</button></div></header>`}
const navItems=[['home','拠点'],['explore','探索'],['party','編成'],['jobs','職業'],['skills','技能'],['inventory','装備'],['forge','鍛冶'],['loop','周回'],['codex','図鑑'],['story','物語'],['settings','設定']];
function nav(){return `<nav class="nav"><div class="nav-inner">${navItems.map(([id,label])=>`<button class="nav-btn ${state.screen===id?'active':''}" data-act="nav" data-id="${id}">${label}</button>`).join('')}</div></nav>`}
function footer(){return `<div class="footer-save"><button class="btn ghost" data-act="save">セーブ</button><button class="btn ghost" data-act="export">書き出し</button><button class="btn ghost" data-act="import">読み込み</button><button class="btn ghost" data-act="home">拠点へ</button></div>`}

function titleScreen(){playBgm('home');return `<main class="page" style="min-height:calc(100vh - 80px);display:grid;place-items:center"><section class="card" style="width:min(760px,100%);overflow:hidden"><div style="min-height:270px;background:linear-gradient(135deg,rgba(10,12,25,.2),rgba(32,20,70,.45)),url('${ASSET.region('prism_sanctum')}') center/cover;display:grid;place-items:center;text-align:center;padding:26px"><div><div class="crumb">OMNIL — CHRONICLE OF BALANCE</div><h1 style="font-size:clamp(34px,7vw,65px);margin:8px 0;letter-spacing:.08em" class="rainbow">全零〈オムニル〉</h1><p class="page-lead" style="max-width:540px;margin:12px auto;color:#e2eaff">白と黒、そして虹の継承者たち。<br>終わりなき遺跡で、己だけの継承を組み上げろ。</p></div></div><div class="card-pad"><div class="grid-2"><button class="btn primary full" data-act="start-game">${state.flags.seenTitle?'旅を続ける':'新たな継承を始める'}</button><button class="btn secondary full" data-act="title-settings">音量・セーブ設定</button></div><p class="tiny muted" style="text-align:center;margin:12px 0 0">静的Web版／ローカルセーブ対応／PC・スマホ対応</p></div></section></main>`}

function renderHome(){playBgm('home');const goals=nextGoals();return `<main class="page"><div class="page-head"><div><div class="crumb">HOME / ADVENTURERS' GUILD</div><h1 class="page-title">枝角亭・作戦卓</h1><p class="page-lead">次の解放条件を確認し、3人の継承を整えて出発しよう。</p></div><div class="button-row"><button class="btn primary" data-act="nav" data-id="explore">探索へ出発</button><button class="btn secondary" data-act="nav" data-id="loop">オート周回</button></div></div><div class="layout-2"><section class="card"><div class="accent-line"></div><div class="card-pad"><div class="section-title"><span>全零〈オムニル〉</span><small>現在の編成</small></div><div class="hero-grid">${Object.values(state.heroes).map(h=>heroCard(h,{selectable:true})).join('')}</div></div></section><section class="card"><div class="card-pad"><div class="section-title"><span>次の継承目標</span><small>達成すると自動解放</small></div><div class="goal-list">${goals.map(g=>`<div class="goal"><i class="goal-dot"></i><div class="goal-body"><div class="goal-title">${g.title}</div><div class="goal-desc">${g.desc}</div>${g.progress!=null?`<div class="progress"><i style="width:${clamp(g.progress,0,100)}%"></i></div>`:''}</div><button class="btn ghost tiny-btn" data-act="${g.act}" data-id="${g.id||''}">${g.btn||'見る'}</button></div>`).join('')}</div></div></section></div><section class="section"><h2 class="section-title">遠征準備 <small>ビルドの長所と注意点</small></h2><div class="grid-3">${Object.values(state.heroes).map(h=>buildInsightCard(h)).join('')}</div></section><section class="section"><h2 class="section-title">最近の記録 <small>進行・討伐・報酬</small></h2><div class="layout-2"><div class="card card-pad"><div class="grid-4"><div class="card-soft"><small class="muted">総討伐</small><b style="display:block;font-size:22px">${fmt(state.meta.kills)}</b></div><div class="card-soft"><small class="muted">ボス撃破</small><b style="display:block;font-size:22px">${fmt(state.meta.bosses)}</b></div><div class="card-soft"><small class="muted">鍛冶回数</small><b style="display:block;font-size:22px">${fmt(state.meta.forge)}</b></div><div class="card-soft"><small class="muted">所持装備</small><b style="display:block;font-size:22px">${fmt(state.inventory.length)}</b></div></div></div><div class="card card-pad"><div class="small">主な素材</div><div class="tag-row">${Object.entries(state.meta.materials).map(([k,v])=>`<span class="tag">${k} ${fmt(v)}</span>`).join('')}</div><div class="button-row" style="margin-top:12px"><button class="btn ghost tiny-btn" data-act="nav" data-id="story">物語を確認</button><button class="btn ghost tiny-btn" data-act="nav" data-id="codex">図鑑を確認</button></div></div></div></section></main>`}
function buildInsightCard(hero){const d=heroDef(hero.id),j=findJob(hero.job),r=raceDef(hero.race),s=getHeroStats(hero);const good=j.tag==='shield'?'防壁・挑発が得意':j.tag==='crit'?'会心・急所攻撃が得意':j.tag==='evasion'?'回避・先制が得意':j.tag==='heal'?'回復・解除が得意':j.tag==='magic'?'属性魔法が得意':j.tag==='status'?'弱体・状態異常が得意':j.tag==='summon'?'召喚・追撃が得意':'前線の安定が得意';const weak=j.tag==='shield'?'魔法連打に注意':j.tag==='crit'?'防御の高い敵に注意':j.tag==='evasion'?'必中攻撃に注意':j.tag==='heal'?'瞬間火力不足に注意':j.tag==='magic'?'MP枯渇に注意':'属性耐性に注意';return `<article class="card card-pad"><div style="display:flex;gap:9px;align-items:center"><img class="hero-sprite" style="width:52px;height:52px" src="${ASSET.hero(hero.id)}"><div><b>${d.name}</b><div class="tiny muted">${j.name} Lv${jobLevel(hero)} ／ ${r.name}</div></div></div><p class="small green">強み：${good}</p><p class="small red">注意：${weak}</p><p class="tiny muted">${statText(s)}</p><button class="btn ghost tiny-btn full" data-act="hero-detail" data-id="${hero.id}">ビルド詳細</button></article>`}
function nextGoals(){const r=REGIONS.find(x=>!regionUnlocked(x.id));const adv=JOBS.find(j=>j.tier==='advanced'&&!jobUnlocked(j.id));const race=RACES.find(r=>!raceUnlocked(r.id));const goals=[];if(r)goals.push({title:`地域解放：${r.name}`,desc:r.unlock,progress:state.unlocks.story/Math.max(1,r.story)*100,act:'nav',id:'explore',btn:'地域を見る'});if(adv)goals.push({title:`上級職：${adv.name}`,desc:adv.requiresJobs.length?`${adv.requiresJobs.map(id=>findJob(id).name).join('＋')} をLv10へ`:'特別依頼で解放',progress:adv.requiresJobs.length?adv.requiresJobs.reduce((a,id)=>a+maxJobLevel(id)/10*100,0)/adv.requiresJobs.length:0,act:'nav',id:'jobs',btn:'職業を見る'});if(race)goals.push({title:`種族解放：${race.name}`,desc:race.unlock,progress:0,act:'nav',id:'party',btn:'種族を見る'});goals.push({title:'装備を鍛える',desc:'鍛冶で装備を強化し、基礎性能を伸ばす。',progress:Math.min(100,state.meta.forge/3*100),act:'nav',id:'forge',btn:'鍛冶へ'});return goals.slice(0,4)}

function renderExplore(){playBgm('field');return `<main class="page"><div class="page-head"><div><div class="crumb">EXPLORE / REGIONS</div><h1 class="page-title">探索地域</h1><p class="page-lead">危険要素と主要ドロップを確認してから出発する。ボス撃破で次の地域と継承が開く。</p></div><div class="stat-pill">総合戦力 <b>${fmt(partyPower())}</b></div></div><section class="region-grid">${REGIONS.map(regionCard).join('')}</section></main>`}
function regionCard(r){const unlocked=regionUnlocked(r.id), power=Math.round(r.level*260+400);return `<article class="region-card ${unlocked?'':'locked-card'}"><div class="region-bg" style="background-image:url('${ASSET.region(r.bg)}')"></div><div class="region-content"><div class="region-name">${r.name}</div><div class="region-level">推奨戦力 ${fmt(power)}　危険度 ${'◆'.repeat(Math.min(5,Math.ceil(r.level/8)))}</div><p class="region-desc">${r.desc}</p><div class="enemy-faces">${r.enemies.map(id=>`<img class="enemy-face" src="${ASSET.enemy(id)}" alt="">`).join('')}<img class="enemy-face" src="${ASSET.enemy(r.boss)}" alt="ボス"></div><div class="region-meta"><div class="meta-box"><b>危険</b>${r.danger}</div><div class="meta-box"><b>推奨</b>${r.resist}</div><div class="meta-box"><b>報酬</b>${r.reward}</div><div class="meta-box"><b>周回目安</b>${r.time}</div></div>${unlocked?`<div class="button-row"><button class="btn primary" data-act="region-detail" data-id="${r.id}">出発準備</button><button class="btn ghost" data-act="quick-battle" data-id="${r.id}">通常戦</button></div>`:`<div class="lock-overlay">未解放<br><small>${r.unlock}</small></div>`}</div></article>`}

function renderParty(){playBgm('home');const h=state.heroes[state.ui.selectedHero];return `<main class="page"><div class="page-head"><div><div class="crumb">PARTY / BUILD</div><h1 class="page-title">パーティ編成</h1><p class="page-lead">種族・職業・技能・装備を合わせ、役割の噛み合わせを整える。</p></div></div><section class="hero-grid">${Object.values(state.heroes).map(x=>heroCard(x,{selectable:true})).join('')}</section><section class="layout-2 section"><article class="card card-pad"><div class="section-title"><span>${heroDef(h.id).name}の継承</span><small>${heroDef(h.id).role}</small></div>${renderHeroBuild(h)}</article><aside class="card card-pad"><div class="section-title"><span>ビルド操作</span><small>変更は即時反映</small></div><div class="button-row"><button class="btn primary full" data-act="choose-race" data-id="${h.id}">種族を変更</button><button class="btn primary full" data-act="choose-job" data-id="${h.id}">職業を変更</button><button class="btn secondary full" data-act="choose-skills" data-id="${h.id}">技能を編集</button><button class="btn secondary full" data-act="nav" data-id="inventory">装備を編集</button></div><div class="card-soft" style="margin-top:14px"><b class="small">現在の方向性</b><p class="tiny muted">${buildDirection(h)}</p></div></aside></section></main>`}
function baseSkillCard(heroId){const b=baseSkillDef(heroId);return `<section class="base-skill-card"><div class="base-skill-icon">${b.icon==='prism'?'✦':b.icon==='creation'?'✧':'✕'}</div><div><div class="base-skill-head"><span>変更不可・枠消費なし</span><b>${b.name}</b></div><p>${b.desc}</p><div class="tag-row">${b.growth.map(x=>`<span class="tag">${x}</span>`).join('')}</div><p class="tiny muted">相性：${b.synergy}<br>方向性：${b.builds}</p></div></section>`}
function renderHeroBuild(h){const s=getHeroStats(h),race=raceDef(h.race),job=findJob(h.job),base=baseSkillDef(h.id);return `${baseSkillCard(h.id)}<div class="grid-2"><div><div class="card-soft"><b>${race.name}</b><p class="tiny muted">${race.flavor}</p><p class="tiny green">${race.passive}</p><p class="tiny">向く：${race.good} ／ 苦手：${race.weak}</p></div><div class="card-soft" style="margin-top:10px"><b>${job.name} Lv${jobLevel(h)}</b><p class="tiny muted">${job.desc}</p><p class="tiny green">${job.passive}</p><div class="progress"><i style="width:${jobProgress(h)}%"></i></div><small class="muted">職業経験 ${jobProgress(h)}/120</small></div></div><div class="card-soft"><b>最終ステータス</b><dl class="kv"><dt>HP / MP</dt><dd>${fmt(s.hp)} / ${fmt(s.mp)}</dd><dt>物攻 / 魔攻</dt><dd>${fmt(s.atk)} / ${fmt(s.mag)}</dd><dt>防御 / 魔防</dt><dd>${fmt(s.def)} / ${fmt(s.res)}</dd><dt>速度 / 会心 / 回避</dt><dd>${fmt(s.spd)} / ${fmt(s.crit)}% / ${fmt(s.evade)}%</dd><dt>武器 / 防具</dt><dd>${job.weapon} / ${job.armor}</dd></dl></div></div><div class="section-title" style="margin-top:14px"><span>装備技能</span><small>戦闘で使う4枠</small></div><div class="skills-row">${h.skills.map(id=>skillButton(getSkill(id),false)).join('')}</div>`}
function buildDirection(h){const job=findJob(h.job),race=raceDef(h.race),items=heroItems(h);const tags=[job.tag,race.tag,...items.map(i=>i.affix)].filter(Boolean);return `主軸：${[...new Set(tags)].join('・')}。${job.passive}。装備と技能を同系統に寄せると性能が伸びます。`}

function renderJobs(){playBgm('home');return `<main class="page"><div class="page-head"><div><div class="crumb">JOBS / SUCCESSION TREE</div><h1 class="page-title">職業継承</h1><p class="page-lead">通常職を2つ極めて上級職へ。上級職を3つ極め、超級職の扉を開く。</p></div><div class="button-row"><button class="btn secondary" data-act="job-guide">解放条件の見方</button><button class="btn primary" data-act="nav" data-id="party">編成へ</button></div></div><div class="job-tree">${['normal','advanced','transcend'].map(t=>{const label={normal:'通常職',advanced:'上級職',transcend:'超級職'}[t];return `<section class="job-tier"><h3>${label} <small class="muted">${JOBS.filter(x=>x.tier===t&&jobUnlocked(x.id)).length}/${JOBS.filter(x=>x.tier===t).length} 解放</small></h3><div class="job-grid">${JOBS.filter(x=>x.tier===t).map(jobCard).join('')}</div></section>`}).join('')}</div></main>`}
function jobCard(j){const unlocked=jobUnlocked(j.id), active=Object.values(state.heroes).some(h=>h.job===j.id);let req='';if(j.tier==='normal')req=j.requiresStory?`物語段階 ${j.requiresStory} で解放`:'開始時または初期依頼';else req=j.requiresJobs.length?`${j.requiresJobs.map(id=>`${findJob(id).name} Lv${maxJobLevel(id)}/10`).join(' ＋ ')}`:'特別依頼';return `<button class="job-card ${unlocked?'':'locked'} ${active?'active':''}" data-act="job-detail" data-id="${j.id}"><span class="job-tier-badge">${j.tier==='normal'?'通常':j.tier==='advanced'?'上級':'超級'}</span><div class="job-name">${unlocked?'':'未解放　'}${j.name}</div><div class="job-desc">${j.desc}</div><div class="tag-row">${tagHtml([j.tag,j.weapon,j.armor])}</div><div class="job-level">${unlocked?`解放済み　最高Lv${maxJobLevel(j.id)}`:`条件：${req}`}</div></button>`}

function renderSkills(){
  playBgm('home');
  const h=state.heroes[state.ui.selectedHero];
  const f=(state.ui.skillsFilter||'').toLowerCase();
  const tag=state.ui.skillsTag||'all';
  const filtered=SKILLS.filter(s=>(!f||s.name.toLowerCase().includes(f)||s.tags.join('').includes(f))&&(tag==='all'||s.tags.includes(tag)));
  const pageSize=80, pages=Math.max(1,Math.ceil(filtered.length/pageSize));
  state.ui.skillsPage=clamp(state.ui.skillsPage||0,0,pages-1);
  const list=filtered.slice(state.ui.skillsPage*pageSize,state.ui.skillsPage*pageSize+pageSize);
  return `<main class="page"><div class="page-head"><div><div class="crumb">SKILLS / ARCHIVE</div><h1 class="page-title">技能書庫</h1><p class="page-lead">技能は500種。習得後、編成画面で4枠へ装備できる。</p></div><div class="stat-pill">魂片 <b>${fmt(state.meta.shards)}</b></div></div><section class="card card-pad"><div class="section-title"><span>選択中：${heroDef(h.id).name}</span><button class="btn ghost tiny-btn" data-act="nav" data-id="party">編成を開く</button></div><div class="skills-row">${h.skills.map(s=>skillButton(getSkill(s),true)).join('')}</div></section><section class="section"><div class="filters"><input class="input" data-bind="skillsFilter" value="${esc(state.ui.skillsFilter)}" placeholder="技能名・効果で検索"><select class="select" data-bind="skillsTag"><option value="all">全カテゴリ</option>${['物理','魔法','回復','防壁','毒','出血','火傷','凍結','感電','召喚','強化','解除','反撃','虹'].map(x=>`<option ${state.ui.skillsTag===x?'selected':''}>${x}</option>`).join('')}</select><button class="btn secondary" data-act="apply-skill-filter">絞り込む</button></div><div class="section-title"><small>表示 ${state.ui.skillsPage*pageSize+1}〜${Math.min(filtered.length,(state.ui.skillsPage+1)*pageSize)} / ${filtered.length}（全500）</small><div class="button-row"><button class="btn ghost tiny-btn" data-act="skill-page" data-id="-1" ${state.ui.skillsPage===0?'disabled':''}>前へ</button><span class="tag">${state.ui.skillsPage+1}/${pages}</span><button class="btn ghost tiny-btn" data-act="skill-page" data-id="1" ${state.ui.skillsPage>=pages-1?'disabled':''}>次へ</button></div></div><div class="skill-grid">${list.map(s=>skillCard(s,h)).join('')}</div></section></main>`;
}
function skillButton(s,selected){return `<button class="skill-button ${selected?'selected':''}" data-act="skill-detail" data-id="${s.id}"><b>${s.name}</b><small>${s.element} / MP ${s.mp} / CD ${s.cd}</small><small class="cost">${s.tags.join('・')}</small></button>`}
function skillCard(s,h){const known=skillKnown(s.id),can=jobLevel(h)>=s.rank*2;return `<article class="skill-card ${known?'learned':''}"><b>${s.name}</b><div class="skill-meta">${tagHtml([s.element,...s.tags.slice(0,2)])}</div><p>${s.desc}</p><p class="tiny">威力/効果 ${s.coeff}　MP ${s.mp}　CD ${s.cd}　必要Lv ${s.rank*2}</p>${known?`<button class="btn ghost tiny-btn full" data-act="equip-skill" data-id="${s.id}">装備する</button>`:`<button class="btn ${can?'good':'ghost'} tiny-btn full" data-act="learn-skill" data-id="${s.id}" ${can?'':'disabled'}>${can?`魂片${s.rank*4}で習得`:`${findJob(h.job).name} Lv${s.rank*2}が必要`}</button>`}</article>`}

function inventoryView(){const f=(state.ui.inventoryFilter||'').toLowerCase(), type=state.ui.inventoryType||'all', rare=state.ui.inventoryRarity||'all', tag=state.ui.inventoryTag||'all', min=Number(state.ui.inventoryMinLevel)||0, max=Number(state.ui.inventoryMaxLevel)||0, sort=state.ui.inventorySort||'newest';const arr=state.inventory.filter(inv=>{const d=EQUIP_MAP[inv.id];if(!d)return false;const hay=`${d.name} ${d.tags.join(' ')} ${d.affix} ${d.typeLabel}`.toLowerCase();return (!f||hay.includes(f))&&(type==='all'||d.type===type)&&(rare==='all'||d.rarity===rare)&&(tag==='all'||d.tags.includes(tag))&&d.level>=min&&(!max||d.level<=max);});arr.sort((a,b)=>{const da=EQUIP_MAP[a.id],db=EQUIP_MAP[b.id];if(sort==='rarity')return rarityRank(db.rarity)-rarityRank(da.rarity)||db.level-da.level;if(sort==='level')return db.level-da.level||rarityRank(db.rarity)-rarityRank(da.rarity);if(sort==='value')return saleValue(b)-saleValue(a);if(sort==='upgrade')return (b.upgrade||0)-(a.upgrade||0)||rarityRank(db.rarity)-rarityRank(da.rarity);return (b.acquiredAt||0)-(a.acquiredAt||0)});return arr}
function raritySummary(){return RARITY_ORDER.map(r=>`${r} ${state.inventory.filter(i=>EQUIP_MAP[i.id]?.rarity===r).length}`).join(' ／ ')}
function renderInventory(){playBgm('home');const h=state.heroes[state.ui.selectedHero],items=inventoryView(),pageCount=Math.max(1,Math.ceil(items.length/INVENTORY_PAGE_SIZE)),page=clamp(state.ui.inventoryPage||0,0,pageCount-1),slice=items.slice(page*INVENTORY_PAGE_SIZE,page*INVENTORY_PAGE_SIZE+INVENTORY_PAGE_SIZE),selected=new Set(state.ui.inventorySelected||[]),tags=[...new Set(EQUIPMENT.flatMap(e=>e.tags).filter(t=>!['unique'].includes(t)))].slice(0,20),canBulk=(state.ui.inventorySelected||[]).filter(uid=>invItem(uid)).length;state.ui.inventoryPage=page;return `<main class="page"><div class="page-head"><div><div class="crumb">EQUIPMENT / INVENTORY</div><h1 class="page-title">装備庫・一括整理</h1><p class="page-lead">最大10,000個を保持。検索・選択・保護・自動整理で、周回を止めずにビルド候補を残す。</p></div><div class="stat-pill inventory-cap ${state.inventory.length>=MAX_INVENTORY?'danger':''}"><b>${fmt(state.inventory.length)}</b> / ${fmt(MAX_INVENTORY)} 装備</div></div><section class="card card-pad"><div class="inventory-summary"><div><b>レアリティ内訳</b><p class="tiny muted">${raritySummary()}</p></div><div class="button-row"><button class="btn secondary" data-act="open-auto-rules">周回の自動整理設定</button><button class="btn ghost" data-act="inventory-reset-filters">絞り込み解除</button></div></div><div class="filters inventory-filters"><input class="input" data-bind="inventoryFilter" value="${esc(state.ui.inventoryFilter)}" placeholder="装備名・効果・タグで検索"><select class="select" data-bind="inventoryType"><option value="all">全カテゴリ</option>${[...new Set(EQUIPMENT.map(i=>i.type))].map(x=>`<option value="${x}" ${state.ui.inventoryType===x?'selected':''}>${EQUIPMENT.find(i=>i.type===x).typeLabel}</option>`).join('')}</select><select class="select" data-bind="inventoryRarity"><option value="all">全レアリティ</option>${RARITY_ORDER.map(x=>`<option value="${x}" ${state.ui.inventoryRarity===x?'selected':''}>${x}</option>`).join('')}</select><select class="select" data-bind="inventoryTag"><option value="all">全ビルドタグ</option>${tags.map(x=>`<option value="${x}" ${state.ui.inventoryTag===x?'selected':''}>${x}</option>`).join('')}</select><input class="input short-input" type="number" min="0" data-bind="inventoryMinLevel" value="${state.ui.inventoryMinLevel||0}" placeholder="Lv以上"><input class="input short-input" type="number" min="0" data-bind="inventoryMaxLevel" value="${state.ui.inventoryMaxLevel||0}" placeholder="Lv以下"><select class="select" data-bind="inventorySort"><option value="newest" ${state.ui.inventorySort==='newest'?'selected':''}>新着順</option><option value="rarity" ${state.ui.inventorySort==='rarity'?'selected':''}>レアリティ順</option><option value="level" ${state.ui.inventorySort==='level'?'selected':''}>レベル順</option><option value="upgrade" ${state.ui.inventorySort==='upgrade'?'selected':''}>強化順</option><option value="value" ${state.ui.inventorySort==='value'?'selected':''}>売却額順</option></select><button class="btn primary" data-act="apply-inventory-filter">絞り込む</button></div></section><section class="layout-2 section"><article class="card card-pad"><div class="section-title"><span>${heroDef(h.id).name}の装備</span><button class="btn ghost tiny-btn" data-act="choose-hero-inventory">対象変更</button></div><div class="slot-grid">${renderEquipSlots(h)}</div><p class="tiny muted" style="margin:12px 0 0">詳細から装備比較を確認。保護・お気に入りは一括整理の対象外にできます。</p></article><aside class="card card-pad"><div class="section-title"><span>ビルド性能</span><small>${findJob(h.job).name}</small></div>${renderBuildStats(h)}</aside></section><section class="section card card-pad"><div class="section-title"><span>一括操作 <small>選択 ${fmt(canBulk)}件 / 絞り込み ${fmt(items.length)}件</small></span><div class="button-row"><button class="btn ghost tiny-btn" data-act="select-page">表示中を選択</button><button class="btn ghost tiny-btn" data-act="select-filtered">絞り込み全件を選択</button><button class="btn ghost tiny-btn" data-act="invert-selection">選択反転</button><button class="btn ghost tiny-btn" data-act="clear-selection">選択解除</button></div></div><div class="bulk-guards"><label class="checkbox-row"><input type="checkbox" data-bind-check="bulkExcludeEquipped" ${state.ui.bulkExcludeEquipped?'checked':''}>装備中を除外</label><label class="checkbox-row"><input type="checkbox" data-bind-check="bulkExcludeLocked" ${state.ui.bulkExcludeLocked?'checked':''}>保護中を除外</label><label class="checkbox-row"><input type="checkbox" data-bind-check="bulkExcludeFavorite" ${state.ui.bulkExcludeFavorite?'checked':''}>お気に入りを除外</label><label class="checkbox-row"><input type="checkbox" data-bind-check="bulkExcludeUnique" ${state.ui.bulkExcludeUnique?'checked':''}>ユニークを除外</label></div><div class="bulk-actions"><button class="btn warn" data-act="bulk-confirm" data-id="sell" ${canBulk?'':'disabled'}>選択を一括売却</button><button class="btn secondary" data-act="bulk-confirm" data-id="break" ${canBulk?'':'disabled'}>選択を一括分解</button><button class="btn ghost" data-act="bulk-confirm" data-id="lock" ${canBulk?'':'disabled'}>一括保護</button><button class="btn ghost" data-act="bulk-confirm" data-id="unlock" ${canBulk?'':'disabled'}>保護解除</button><button class="btn ghost" data-act="bulk-confirm" data-id="favorite" ${canBulk?'':'disabled'}>お気に入り</button><button class="btn ghost" data-act="bulk-confirm" data-id="unfavorite" ${canBulk?'':'disabled'}>お気に入り解除</button><button class="btn ghost" data-act="bulk-confirm" data-id="junk" ${canBulk?'':'disabled'}>ジャンク指定</button><button class="btn ghost" data-act="bulk-confirm" data-id="unjunk" ${canBulk?'':'disabled'}>ジャンク解除</button></div><div class="quick-rarity-actions"><span class="tiny muted">レアリティ別クイック処理：</span>${RARITY_ORDER.slice(0,5).map(r=>`<button class="btn ghost tiny-btn" data-act="bulk-rarity-confirm" data-id="sell|${r}">${r}を売却</button><button class="btn ghost tiny-btn" data-act="bulk-rarity-confirm" data-id="break|${r}">${r}を分解</button>`).join('')}</div></section><section class="section"><div class="section-title"><span>装備一覧 <small>${items.length?`${page*INVENTORY_PAGE_SIZE+1}〜${Math.min(items.length,(page+1)*INVENTORY_PAGE_SIZE)} / ${fmt(items.length)}`:'0件'}</small></span><div class="button-row"><button class="btn ghost tiny-btn" data-act="inventory-page" data-id="-1" ${page===0?'disabled':''}>前へ</button><span class="tag">${page+1}/${pageCount}</span><button class="btn ghost tiny-btn" data-act="inventory-page" data-id="1" ${page>=pageCount-1?'disabled':''}>次へ</button></div></div><div class="table-wrap"><table class="data-table inventory-table"><thead><tr><th><input type="checkbox" data-select-page-toggle ${slice.length&&slice.every(i=>selected.has(i.uid))?'checked':''} aria-label="表示中を全選択"></th><th>装備</th><th>カテゴリ</th><th>性能・効果</th><th>強化</th><th>状態</th><th></th></tr></thead><tbody>${slice.map(inv=>itemRow(inv,h,selected.has(inv.uid))).join('')||'<tr><td colspan="7">該当する装備がありません。</td></tr>'}</tbody></table></div></section></main>`}
function renderEquipSlots(h){const slots=['onehand_sword','twohand_sword','dagger','axe','spear','bow','staff','tome','shield','light_armor','heavy_armor','robe','helm','hat','ring','necklace','bracelet','charm','relic'];const seen=[];return slots.filter(t=>{const d=EQUIPMENT.find(x=>x.type===t);if(!d||seen.includes(d.typeLabel))return false;seen.push(d.typeLabel);return true}).map(t=>{const uid=h.equip?.[t],it=itemDefFromUid(uid),label=EQUIPMENT.find(x=>x.type===t)?.typeLabel||t;return `<button class="equip-slot" data-act="slot-detail" data-id="${t}"><b>${label}</b>${it?`<img src="${ASSET.icon(it.icon)||''}" alt=""><small>${it.name}</small><small class="${rarityClass(it.rarity)}">${it.rarity} +${invItem(uid)?.upgrade||0}</small>`:'<small>未装備</small>'}</button>`}).join('')}
function renderBuildStats(h){const s=getHeroStats(h);return `<dl class="kv"><dt>HP</dt><dd>${fmt(s.hp)}</dd><dt>MP</dt><dd>${fmt(s.mp)}</dd><dt>物理攻撃</dt><dd>${fmt(s.atk)}</dd><dt>魔法攻撃</dt><dd>${fmt(s.mag)}</dd><dt>防御 / 魔防</dt><dd>${fmt(s.def)} / ${fmt(s.res)}</dd><dt>会心 / 回避</dt><dd>${fmt(s.crit)}% / ${fmt(s.evade)}%</dd><dt>追加効果</dt><dd>防壁+${s.mods.barrier}% / 吸収+${s.mods.lifesteal}% / 状態+${s.mods.statusPower}%</dd><dt>周回効率</dt><dd>ドロップ+${s.mods.dropRate}% / 経験+${s.mods.xpRate}%</dd></dl>`}
function itemRow(inv,h,selected=false){const d=EQUIP_MAP[inv.id],equipped=isEquippedUid(inv.uid),flags=[equipped?'装備中':'',inv.locked?'保護':'',inv.favorite?'お気に入り':'',inv.junk?'ジャンク':''].filter(Boolean).join('・')||'—';return `<tr><td><input type="checkbox" data-select-item="${inv.uid}" ${selected?'checked':''} aria-label="${esc(d.name)}を選択"></td><td><img class="item-icon" src="${ASSET.icon(d.icon)||''}" alt=""><b class="${rarityClass(d.rarity)}">${d.name}</b><br><small>${d.set}</small></td><td>${d.typeLabel}<br><small class="${rarityClass(d.rarity)}">${d.rarity}</small></td><td>${statLine(d.stats)}<br><small class="muted">${d.desc}</small></td><td>+${inv.upgrade||0}</td><td>${flags}</td><td><button class="btn ghost tiny-btn" data-act="item-detail" data-id="${inv.uid}">詳細</button></td></tr>`}
function rarityClass(r){return ({'コモン':'rarity-common','アンコモン':'rarity-uncommon','レア':'rarity-rare','エピック':'rarity-epic','レジェンダリー':'rarity-legendary','ユニーク':'rarity-unique'})[r]||'rarity-common'}
function statLine(obj){return Object.entries(obj||{}).filter(([,v])=>v).slice(0,6).map(([k,v])=>`${statLabel(k)}+${v}`).join(' / ')}
function statLabel(k){return ({hp:'HP',mp:'MP',atk:'物攻',mag:'魔攻',def:'防御',res:'魔防',spd:'速度',crit:'会心',evade:'回避',barrier:'防壁',lifesteal:'吸収',statusPower:'状態異常',dropRate:'ドロップ',xpRate:'経験',prism:'調律'})[k]||k}

function renderForge(){playBgm('home');const candidates=state.inventory.slice().sort((a,b)=>b.upgrade-a.upgrade).slice(0,30);return `<main class="page"><div class="page-head"><div><div class="crumb">FORGE / REINFORCEMENT</div><h1 class="page-title">鍛冶工房</h1><p class="page-lead">強化は装備の基礎性能を伸ばす。低レアも、用途を見極めれば終盤まで役立つ。</p></div><div class="stat-pill">鉄片 <b>${fmt(state.meta.materials['鉄片']||0)}</b></div></div><section class="layout-2"><article class="card card-pad"><h2 class="section-title">鍛冶の方針 <small>素材は探索で補充</small></h2><div class="card-soft"><b>通常強化</b><p class="small muted">基礎ステータスが強化段階ごとに8%ずつ上昇します。失敗はありません。</p><div class="tag-row"><span class="tag">鉄片 2 + Gold 35</span><span class="tag">最大 +10</span><span class="tag">低レアも対象</span></div></div><div class="card-soft" style="margin-top:10px"><b>ビルドの考え方</b><p class="small muted">会心、状態異常、防壁、周回効率など、数値の高さだけではない追加効果を揃えてください。</p></div></article><article class="card card-pad"><h2 class="section-title">鍛冶実績 <small>解放条件にも使用</small></h2><div class="grid-2"><div class="card-soft"><small class="muted">強化回数</small><b style="font-size:22px;display:block">${fmt(state.meta.forge)}</b></div><div class="card-soft"><small class="muted">次の目標</small><b class="small" style="display:block">${state.meta.forge<5?'5回でドワーフ解放':'鍛冶の熟練者'}</b></div></div></article></section><section class="section"><div class="table-wrap"><table class="data-table"><thead><tr><th>装備</th><th>現在性能</th><th>強化後</th><th>必要素材</th><th></th></tr></thead><tbody>${candidates.map(inv=>forgeRow(inv)).join('')}</tbody></table></div></section></main>`}
function forgeRow(inv){const d=EQUIP_MAP[inv.id],level=inv.upgrade||0,cost=2+level*2,gold=35+level*20;const current=Object.fromEntries(Object.entries(d.stats).map(([k,v])=>[k,Math.floor(v*(1+level*.08))]));const next=Object.fromEntries(Object.entries(d.stats).map(([k,v])=>[k,Math.floor(v*(1+(level+1)*.08))]));return `<tr><td><img class="item-icon" src="${ASSET.icon(d.icon)}"><b class="${rarityClass(d.rarity)}">${d.name}</b> +${level}</td><td>${statLine(current)}</td><td class="diff-up">${statLine(next)}</td><td>鉄片 ${cost} / G ${gold}</td><td><button class="btn good tiny-btn" data-act="forge" data-id="${inv.uid}" ${level>=10?'disabled':''}>${level>=10?'最大':'強化'}</button></td></tr>`}

function autoRuleSummary(l){return RARITY_ORDER.map(r=>`<span class="rule-chip ${l.autoRules[r]}">${r}：${l.autoRules[r]==='sell'?'売却':l.autoRules[r]==='break'?'分解':'保持'}</span>`).join('')}
function renderLoop(){playBgm('field');const l=state.loop,r=findRegion(l.regionId);const materialOptions=Object.keys(state.meta.materials).length?Object.keys(state.meta.materials):['草原の繊維','鉄片'];return `<main class="page"><div class="page-head"><div><div class="crumb">AUTO LOOP / EXPEDITION</div><h1 class="page-title">オート周回</h1><p class="page-lead">周回、停止条件、自動整理を一画面で確認。保持する装備だけを残して長時間周回できる。</p></div><div class="button-row">${l.running?`<button class="btn warn" data-act="stop-loop">周回を停止</button>`:`<button class="btn good" data-act="start-loop">周回を開始</button>`}</div></div><section class="layout-2"><article class="card card-pad"><div class="section-title"><span>周回設定</span><small>${l.running?'実行中':'待機中'}</small></div><div class="field"><label>地域</label><select class="select" data-bind="loopRegion">${REGIONS.filter(x=>regionUnlocked(x.id)).map(x=>`<option value="${x.id}" ${x.id===l.regionId?'selected':''}>${x.name}（推奨${fmt(x.level*260+400)}）</option>`).join('')}</select></div><div class="grid-2" style="margin-top:10px"><label class="checkbox-row"><input type="checkbox" data-bind-check="loopBoss" ${l.boss?'checked':''}>ボス周回</label><label class="checkbox-row"><input type="checkbox" data-bind-check="loopUnlimited" ${l.unlimited?'checked':''}>無制限</label></div><div class="field" style="margin-top:10px"><label>周回回数</label><input class="input" type="number" min="1" max="9999" data-bind="loopTarget" value="${l.target}" ${l.unlimited?'disabled':''}></div><div class="section-title" style="margin-top:16px"><span>停止条件</span><small>1つでも達成で停止</small></div><div class="grid-2"><label class="checkbox-row"><input type="checkbox" data-bind-check="loopRare" ${l.stopRare?'checked':''}>レア以上獲得で停止</label><label class="checkbox-row"><input type="checkbox" data-bind-check="loopDeath" ${l.stopDeath?'checked':''}>戦闘不能で停止</label><label class="checkbox-row"><input type="checkbox" data-bind-check="loopFull" ${l.stopFull?'checked':''}>所持品10,000で停止</label><label class="checkbox-row"><input type="checkbox" checked disabled>手動停止を常時許可</label></div><div class="grid-2" style="margin-top:10px"><div class="field"><label>終了HP%（0で無効）</label><input class="input" type="number" min="0" max="100" data-bind="loopStopHp" value="${l.stopHp||0}"></div><div class="field"><label>終了MP%（0で無効）</label><input class="input" type="number" min="0" max="100" data-bind="loopStopMp" value="${l.stopMp||0}"></div><div class="field"><label>取得経験値（0で無効）</label><input class="input" type="number" min="0" data-bind="loopStopXp" value="${l.stopXp||0}"></div><div class="field"><label>指定装備名を取得</label><input class="input" data-bind="loopStopItem" value="${esc(l.stopItem||'')}" placeholder="例：炎の剣"></div><div class="field"><label>素材目標数</label><input class="input" type="number" min="0" data-bind="loopMaterialCount" value="${l.stopMaterialCount||0}"></div><div class="field"><label>目標素材</label><select class="select" data-bind="loopMaterial">${materialOptions.map(x=>`<option value="${x}" ${l.stopMaterial===x?'selected':''}>${x}</option>`).join('')}</select></div></div><div class="card-soft" style="margin-top:13px"><b>${r.name}</b><p class="tiny muted">危険：${r.danger}<br>推奨：${r.resist}<br>主な報酬：${r.reward}</p></div></article><aside class="card card-pad"><div class="section-title"><span>自動整理</span><button class="btn secondary tiny-btn" data-act="open-auto-rules">詳細設定</button></div><p class="tiny muted">保持条件に一致する装備は、レアリティ設定より優先して保護します。</p><div class="rule-chip-row">${autoRuleSummary(l)}</div><div class="card-soft" style="margin-top:10px"><small>保持条件</small><p class="tiny">${l.keepTypes.length?`カテゴリ：${l.keepTypes.join('・')}`:'カテゴリ指定なし'}<br>${l.keepTags.length?`タグ：${l.keepTags.join('・')}`:'タグ指定なし'}<br>${l.keepAffixes.length?`効果：${l.keepAffixes.join('・')}`:'効果指定なし'}<br>${l.keepMinLevel?`装備Lv${l.keepMinLevel}以上を保持`:'レベル指定なし'}</p></div><div class="section-title" style="margin-top:14px"><span>今回の戦績</span><small>${l.lastStopReason?`最終停止：${l.lastStopReason}`:'リアルタイム更新'}</small></div><div class="loop-status"><div class="loop-metric"><small>周回</small><b>${fmt(l.run)}</b></div><div class="loop-metric"><small>勝利</small><b class="green">${fmt(l.wins)}</b></div><div class="loop-metric"><small>戦闘不能</small><b class="red">${fmt(l.deaths)}</b></div><div class="loop-metric"><small>取得Gold</small><b class="gold">${fmt(l.gold)}</b></div></div><div class="loop-status compact"><div class="loop-metric"><small>保持</small><b>${fmt(l.autoKept||0)}</b></div><div class="loop-metric"><small>自動売却</small><b>${fmt(l.autoSold||0)}</b></div><div class="loop-metric"><small>自動分解</small><b>${fmt(l.autoBroken||0)}</b></div><div class="loop-metric"><small>整理Gold</small><b>${fmt(l.autoGold||0)}</b></div></div><div class="section-title" style="margin-top:16px"><span>周回ログ</span><button class="btn ghost tiny-btn" data-act="clear-loop-log">消去</button></div><div class="battle-log">${l.logs.slice(-12).map(x=>`<p>${x}</p>`).join('')||'<p class="muted">まだ記録はありません。</p>'}</div><div class="section-title" style="margin-top:14px"><span>最近のドロップ</span></div><div class="loot-list">${l.drops.slice(-5).reverse().map(x=>`<div class="loot-line"><span class="${rarityClass(x.rarity)}">${x.name}</span><span>${x.rarity}</span></div>`).join('')||'<div class="empty">まだ装備を獲得していません。</div>'}</div></aside></section></main>`}
function renderCodex(){
  playBgm('home');
  const unlockedEnemies=ENEMIES.filter(e=>state.meta.kills>0).slice(0,Math.min(ENEMIES.length,Math.max(3,Math.ceil(state.meta.kills/5))));
  const pageSize=18,pages=Math.ceil(EQUIPMENT.length/pageSize),page=clamp(state.ui.codexPage||0,0,pages-1),catalog=EQUIPMENT.slice(page*pageSize,page*pageSize+pageSize);
  return `<main class="page"><div class="page-head"><div><div class="crumb">CODEX / ARCHIVE</div><h1 class="page-title">継承図鑑</h1><p class="page-lead">種族、敵、全装備カタログ、実績を確認する。</p></div></div><section class="layout-2"><article class="card card-pad"><div class="section-title"><span>種族</span><small>${state.unlocks.races.length}/${RACES.length} 解放</small></div><div class="race-grid">${RACES.map(raceCard).join('')}</div></article><article class="card card-pad"><div class="section-title"><span>依頼・実績</span><small>${state.unlocks.quests.length}/${QUESTS.length} 達成</small></div><div class="quest-list">${QUESTS.map(q=>questCard(q)).join('')}</div></article></section><section class="section"><h2 class="section-title">敵図鑑 <small>討伐が進むと詳細が見える</small></h2><div class="grid-4">${unlockedEnemies.map(e=>`<article class="card card-pad"><img class="enemy-face" style="width:64px;height:64px" src="${ASSET.enemy(e.id)}"><b style="display:block;margin-top:7px">${e.name}</b><p class="tiny muted">役割：${e.role}<br>属性：${e.element}</p></article>`).join('')}</div></section><section class="section"><div class="section-title"><span>装備図鑑 <small>${page*pageSize+1}〜${Math.min(EQUIPMENT.length,(page+1)*pageSize)} / ${EQUIPMENT.length}</small></span><div class="button-row"><button class="btn ghost tiny-btn" data-act="codex-page" data-id="-1" ${page===0?'disabled':''}>前へ</button><span class="tag">${page+1}/${pages}</span><button class="btn ghost tiny-btn" data-act="codex-page" data-id="1" ${page>=pages-1?'disabled':''}>次へ</button></div></div><div class="table-wrap"><table class="data-table"><thead><tr><th>装備</th><th>分類</th><th>性能</th><th>ビルド効果</th></tr></thead><tbody>${catalog.map(d=>`<tr data-act="catalog-detail" data-id="${d.id}"><td><img class="item-icon" src="${ASSET.icon(d.icon)}"><b class="${rarityClass(d.rarity)}">${d.name}</b></td><td>${d.typeLabel}</td><td>${statLine(d.stats)}</td><td>${d.desc}</td></tr>`).join('')}</tbody></table></div></section></main>`;
}
function raceCard(r){const unlocked=raceUnlocked(r.id),active=Object.values(state.heroes).some(h=>h.race===r.id);return `<button class="race-card ${unlocked?'':'locked'} ${active?'active':''}" data-act="race-detail" data-id="${r.id}"><b>${unlocked?'':'未解放　'}${r.name}</b><p>${unlocked?r.flavor:`解放条件：${r.unlock}`}</p>${unlocked?`<div class="race-stat">${r.passive}</div>`:''}</button>`}
function questCard(q){const done=state.unlocks.quests.includes(q.id);return `<article class="quest-card ${done?'done':''}"><h4>${done?'達成　':''}${q.name}</h4><p>${q.desc}</p><div class="tiny ${done?'green':'gold'}">${done?'達成済み':'条件：'+q.goal}<br>報酬：${q.reward}</div></article>`}

function renderStory(){playBgm('home');const chapters=REGIONS.map((r,i)=>({n:i+1,title:`第${i+1}章　${r.name}`,text:['調律の剣が、草原の風を切る。','森の囁きが、失われた名を呼ぶ。','灰の下に、終わりの記憶が眠る。','白い嵐が、創生の痛みを映す。','砂の海で、黒い影が目を覚ます。','沈んだ書庫に、神話の断片がある。','嵐の塔で、二つの竜が境界を守る。','虹彩の聖域で、すべての継承がひとつになる。'][i],unlocked:state.unlocks.story>=i}));return `<main class="page"><div class="page-head"><div><div class="crumb">STORY / CHRONICLE</div><h1 class="page-title">継承の記録</h1><p class="page-lead">地域のボスを越えるたび、3人の記憶と世界の神話が開く。</p></div></div><section class="timeline">${chapters.map(c=>`<article class="story-card ${c.unlocked?'':'locked'}"><h4>${c.unlocked?'':'未解放　'}${c.title}</h4><p>${c.unlocked?c.text:'この章はまだ閉ざされている。前の地域のボスを撃破しよう。'}</p></article>`).join('')}</section></main>`}

function renderSettings(){playBgm('home');return `<main class="page"><div class="page-head"><div><div class="crumb">SETTINGS / SAVE</div><h1 class="page-title">設定とセーブ</h1><p class="page-lead">音量、セーブデータ、表示の安全性を管理する。</p></div></div><section class="layout-2"><article class="card card-pad"><h2 class="section-title">音量</h2><div class="field"><label> BGM音量　<span id="bgm-vol-label">${Math.round(state.settings.bgmVol*100)}%</span></label><input type="range" min="0" max="100" value="${Math.round(state.settings.bgmVol*100)}" data-bind-range="bgmVol"></div><div class="field" style="margin-top:14px"><label> SE音量　<span id="se-vol-label">${Math.round(state.settings.seVol*100)}%</span></label><input type="range" min="0" max="100" value="${Math.round(state.settings.seVol*100)}" data-bind-range="seVol"></div><div class="grid-2" style="margin-top:14px"><label class="toggle">BGM <input type="checkbox" data-bind-check="setBgm" ${state.settings.bgm?'checked':''}></label><label class="toggle">SE <input type="checkbox" data-bind-check="setSe" ${state.settings.se?'checked':''}></label></div><div class="button-row" style="margin-top:14px"><button class="btn secondary" data-act="test-bgm">BGM試聴</button><button class="btn secondary" data-act="test-se">SE試聴</button></div></article><article class="card card-pad"><h2 class="section-title">セーブデータ</h2><div class="card-soft"><b>自動セーブ</b><p class="small muted">画面操作、戦闘、周回結果、装備変更の後に自動保存します。</p><p class="tiny">最終保存：${state.lastSaved?new Date(state.lastSaved).toLocaleString('ja-JP'):'まだ保存されていません'}</p></div><div class="button-row" style="margin-top:12px"><button class="btn primary" data-act="save">今すぐセーブ</button><button class="btn secondary" data-act="export">データを書き出す</button><button class="btn secondary" data-act="import">データを読み込む</button><button class="btn warn" data-act="confirm-reset">最初から始める</button></div></article></section></main>`}

function renderBattle(){const b=state.battle;if(!b)return renderExplore();playBgm(b.boss?'boss':'battle');const r=findRegion(b.regionId);return `<main class="page"><div class="page-head"><div><div class="crumb">BATTLE / ${r.name}</div><h1 class="page-title">${b.boss?'ボス戦':'戦闘'}</h1><p class="page-lead">${r.danger}　推奨：${r.resist}</p></div><div class="button-row"><button class="btn ghost" data-act="battle-auto">${b.auto?'オート停止':'オートON'}</button><button class="btn ghost" data-act="confirm-retreat" ${b.result?'disabled':''}>撤退</button></div></div><section class="battle-shell"><div class="battle-bg" style="background-image:url('${ASSET.region(r.bg)}')"></div><div class="battle-ui"><div class="battle-top"><div class="battle-label">${b.boss?'BOSS ':'探索 '} ${r.name}　${b.boss?findEnemy(r.boss).name:''}</div><div class="turn-chip">${b.result?b.result:b.phase==='player'?`${heroDef(b.party[b.currentHero]?.heroId)?.name||''}の行動`:'敵の行動'}</div></div><div class="battle-field"><div class="combat-side">${b.party.map((u,i)=>battleUnitHtml(u,i,false)).join('')}</div><div class="combat-side enemy-side">${b.enemies.map((u,i)=>battleUnitHtml(u,i,true)).join('')}</div></div><div class="battle-log">${b.log.slice(-10).map(x=>`<p>${x}</p>`).join('')}</div>${b.result?battleResultHtml(b):battleActionHtml(b)}</div></section></main>`}
function battleUnitHtml(u,i,enemy){const max=u.maxHp||1;const st=Object.entries(u.effects||{}).filter(([,v])=>v.turns>0).map(([k])=>statusName(k)).join('・')||'通常';return `<div class="combat-unit ${enemy?'enemy':''} ${u.hp<=0?'down':''} ${u.targeted?'targeted':''}"><img src="${enemy?ASSET.enemy(u.enemyId):ASSET.hero(u.heroId,u.hp<=0?'down':'idle')}" alt=""><div class="unit-body"><div class="unit-name">${u.name}</div><div class="bar hp"><i style="width:${clamp(u.hp/max*100,0,100)}%"></i></div><div class="unit-status">HP ${fmt(Math.max(0,u.hp))}/${fmt(max)}　${u.shield?`防壁 ${fmt(u.shield)}　`:''}${st}</div></div></div>`}
function battleActionHtml(b){if(b.phase!=='player')return `<div class="action-panel"><div class="action-hero"><div class="turn-name">敵が行動中…</div><small class="muted">オートでは最適行動を選びます。</small></div><div class="skills-row"><button class="skill-button" disabled><b>行動待機</b><small>敵の行動を処理しています</small></button></div></div>`;const u=b.party[b.currentHero];const h=state.heroes[u.heroId];return `<div class="action-panel"><div class="action-hero"><div class="turn-name">${u.name} の行動</div><small class="muted">MP ${fmt(u.mp)}/${fmt(u.maxMp)}　対象：敵先頭 / 回復は自動選択</small><div class="button-row" style="margin-top:8px"><button class="btn ghost tiny-btn" data-act="battle-defend">防御</button><button class="btn ghost tiny-btn" data-act="battle-auto">${b.auto?'オート停止':'オートON'}</button></div></div><div class="skills-row">${h.skills.map(id=>{const s=getSkill(id);return `<button class="skill-button" data-act="battle-skill" data-id="${id}" ${u.mp<s.mp?'disabled':''}><b>${s.name}</b><small>${s.element} ${s.tags.slice(0,2).join('・')}</small><small class="cost">MP ${s.mp} / CD ${s.cd}</small></button>`}).join('')}</div></div>`}
function battleResultHtml(b){const rewards=b.rewards||{};return `<div class="battle-result"><section class="result-card"><h2 class="${b.result==='勝利'?'gold':'red'}">${b.result}</h2><p class="page-lead">${b.result==='勝利'?'継承はさらに深まった。':'原因を確認し、ビルドを調整しよう。'}</p>${b.result==='勝利'?`<div class="loot-list"><div class="loot-line"><span>Gold</span><b>${fmt(rewards.gold||0)}</b></div><div class="loot-line"><span>経験値</span><b>${fmt(rewards.xp||0)}</b></div><div class="loot-line"><span>素材</span><b>${rewards.material||'—'}</b></div>${(rewards.items||[]).map(i=>`<div class="loot-line"><span class="${rarityClass(i.rarity)}">${i.name}</span><b>${i.rarity}</b></div>`).join('')}</div>`:`<div class="card-soft"><b>敗北の分析</b><p class="small">${battleAdvice(b)}</p></div>`}<div class="button-row" style="justify-content:center"><button class="btn primary" data-act="battle-return">拠点へ戻る</button>${b.result==='勝利'?`<button class="btn secondary" data-act="battle-again">もう一度挑戦</button>`:`<button class="btn secondary" data-act="nav" data-id="party">編成を見直す</button>`}</div></section></div>`}

function render(){const app=$('#app');if(state.screen==='title'){app.innerHTML=titleScreen();return}app.innerHTML=`${topbar()}${nav()}${state.screen==='home'?renderHome():state.screen==='explore'?renderExplore():state.screen==='party'?renderParty():state.screen==='jobs'?renderJobs():state.screen==='skills'?renderSkills():state.screen==='inventory'?renderInventory():state.screen==='forge'?renderForge():state.screen==='loop'?renderLoop():state.screen==='codex'?renderCodex():state.screen==='story'?renderStory():state.screen==='settings'?renderSettings():state.screen==='battle'?renderBattle():renderHome()}${footer()}`}

function statusName(x){return ({poison:'毒',bleed:'出血',burn:'火傷',freeze:'凍結',shock:'感電',weaken:'弱体',silence:'沈黙',regen:'再生',counter:'反撃',taunt:'挑発',haste:'加速',focus:'集中',summon:'召喚'}[x]||x)}
function makeHeroUnit(h){const s=getHeroStats(h);return {type:'hero',heroId:h.id,name:heroDef(h.id).name,stats:s,maxHp:s.hp,hp:s.hp,maxMp:s.mp,mp:s.mp,shield:0,effects:{},cooldowns:{},alive:true,turns:0,baseState:{resonance:0,lastColor:'',marks:0}}}
function makeEnemyUnit(id,regionLevel,boss=false){const e=findEnemy(id);const mult=1+regionLevel*.14+(boss?.75:0);const s={hp:Math.round(e.base.hp*mult),atk:Math.round(e.base.atk*mult),mag:Math.round(e.base.mag*mult),def:Math.round(e.base.def*mult),res:Math.round(e.base.res*mult),spd:e.base.spd+(boss?4:0),crit:boss?8:4,evade:e.role==='回避'?12:2};return {type:'enemy',enemyId:id,name:e.name,role:e.role,element:e.element,stats:s,maxHp:s.hp,hp:s.hp,maxMp:0,mp:0,shield:0,effects:{},cooldowns:{},alive:true,boss}}
function startBattle(regionId,boss=false){if(!regionUnlocked(regionId)){toast('この地域はまだ解放されていません','warn');return}clearTimers();const r=findRegion(regionId);const ids=boss?[r.boss]:[pick(r.enemies),pick(r.enemies),pick(r.enemies)];state.battle={regionId,boss,party:Object.values(state.heroes).map(makeHeroUnit),enemies:ids.map(id=>makeEnemyUnit(id,r.level,boss)),phase:'player',currentHero:0,round:1,log:[`${r.name}へ出発した。`],auto:false,result:null,rewards:null,turnGuard:false};state.screen='battle';saveState();render()}
function unitAlive(u){return u&&u.hp>0}
function liveEnemies(b){return b.enemies.filter(unitAlive)}
function liveParty(b){return b.party.filter(unitAlive)}
function logBattle(b,msg){b.log.push(msg);if(b.log.length>80)b.log.shift()}
function addEffect(u,key,turns,power=0){u.effects[key]={turns,power}}
function tickEffects(b,u){if(!unitAlive(u))return false;let skip=false;for(const [key,v] of Object.entries({...u.effects})){if(!v||v.turns<=0)continue;if(['poison','bleed','burn'].includes(key)){const dmg=Math.max(1,Math.round(v.power));applyDamage(b,null,u,dmg,{direct:true,label:statusName(key),color:'damage'});logBattle(b,`${u.name}は${statusName(key)}で${dmg}ダメージ。`)}if(key==='regen'){const heal=Math.max(1,Math.round(v.power));applyHeal(b,u,heal);logBattle(b,`${u.name}は再生で${heal}回復。`)}if(key==='summon'&&u.type==='hero'){const target=pick(liveEnemies(b));if(target){const dmg=Math.round(v.power);applyDamage(b,u,target,dmg,{direct:true,label:'使い魔',color:'damage'});logBattle(b,`使い魔が${target.name}を追撃。`)}}if(key==='freeze'&&Math.random()<.58){skip=true;logBattle(b,`${u.name}は凍結して動けない。`)}if(key==='shock'&&Math.random()<.25){skip=true;logBattle(b,`${u.name}は感電して行動を乱された。`)}v.turns--;if(v.turns<=0)delete u.effects[key]}return skip}
function applyDamage(b,source,target,amount,{direct=false,label='',color='damage'}={}){if(!unitAlive(target))return 0;let dmg=Math.max(1,Math.round(amount));if(!direct&&target.effects?.weaken?.power)dmg=Math.round(dmg*(1+target.effects.weaken.power));if(target.type==='hero'&&target.effects?.creation)dmg=Math.max(1,Math.round(dmg*(1-target.effects.creation.power)));if(target.type==='hero'&&target.effects?.counter&&source){const ref=Math.max(1,Math.round(dmg*.22+target.stats.def*.22));applyDamage(b,target,source,ref,{direct:true,label:'反撃',color:'damage'});logBattle(b,`${target.name}の反撃！`)}let absorbed=0;if(target.shield>0){absorbed=Math.min(target.shield,dmg);target.shield-=absorbed;dmg-=absorbed;if(absorbed)logBattle(b,`${target.name}の防壁が${absorbed}吸収。`);if(target.type==='hero'&&target.effects?.creation&&target.shield<=0&&absorbed>0){const h=applyHeal(b,target,Math.max(1,Math.round(target.maxHp*.04)));delete target.effects.creation;logBattle(b,`創生の護りが砕け、${target.name}を${h}回復。`)}}target.hp=Math.max(0,target.hp-dmg);if(target.hp<=0){target.alive=false;logBattle(b,`${target.name}は倒れた。`)}if(source?.type==='hero'&&source.stats.mods.lifesteal&&dmg>0){applyHeal(b,source,Math.round(dmg*source.stats.mods.lifesteal/100))}return dmg}
function applyHeal(b,target,amount){if(!unitAlive(target))return 0;const before=target.hp;target.hp=Math.min(target.maxHp,target.hp+Math.max(1,Math.round(amount)));return target.hp-before}
function effectiveness(skill,target){if(skill.element==='無'||!target?.element)return 1;const weak={火:'氷',氷:'雷',雷:'水',光:'闇',闇:'光',虹:'無'};return weak[skill.element]===target.element?1.22:(skill.element===target.element?.82:1)}
function attackAmount(caster,target,skill){const magic=['magic','heal','shield','support'].includes(skill.kind);let offense=magic?caster.stats.mag:caster.stats.atk;let def=magic?target.stats.res:target.stats.def;let amount=(offense*skill.coeff*1.55)/(1+def/100);if(caster.effects.focus){amount*=1+caster.effects.focus.power;delete caster.effects.focus}if(caster.effects.haste)amount*=1.08;if(skill.type==='execute'&&target.hp/target.maxHp<.45)amount*=1.65;if(caster.type==='hero'&&caster.heroId==='kozen'&&skill.type==='prism')amount*=1.15;if(caster.type==='hero'&&caster.stats.mods.prism&&skill.tags.includes('虹'))amount*=1+caster.stats.mods.prism/100;let crit=Math.random()<(caster.stats.crit+(caster.effects.haste?5:0))/100;if(crit)amount*=1.55;amount*=effectiveness(skill,target);return {amount:Math.max(1,Math.round(amount*(.9+Math.random()*.2))),crit}}
function chooseLowest(units){return units.filter(unitAlive).sort((a,b)=>a.hp/a.maxHp-b.hp/b.maxHp)[0]}
function resolveSkill(b,caster,skill,target=null){if(!unitAlive(caster))return; if(caster.mp<skill.mp){logBattle(b,`${caster.name}はMPが足りない。`);return false}caster.mp-=skill.mp;caster.cooldowns[skill.id]=skill.cd;const enemies=liveEnemies(b),party=liveParty(b);const enemyTarget=target||chooseLowest(enemies);const heroTarget=chooseLowest(party);let total=0;const statusPower=1+(caster.stats.mods?.statusPower||0)/100;switch(skill.type){
 case 'damage': case 'execute':{const a=attackAmount(caster,enemyTarget,skill);total=applyDamage(b,caster,enemyTarget,a.amount);logBattle(b,`${caster.name}の${skill.name}${a.crit?'（会心）':''}！ ${enemyTarget.name}へ${total}ダメージ。`);break}
 case 'aoe':{enemies.forEach(t=>{const a=attackAmount(caster,t,{...skill,coeff:skill.coeff*.78});total+=applyDamage(b,caster,t,a.amount)});logBattle(b,`${caster.name}の${skill.name}！ 敵全体へ${total}ダメージ。`);break}
 case 'heal':{const h=applyHeal(b,heroTarget,caster.stats.mag*skill.coeff*1.35);logBattle(b,`${caster.name}の${skill.name}。${heroTarget.name}を${h}回復。`);break}
 case 'regen':{party.forEach(t=>addEffect(t,'regen',3,caster.stats.mag*skill.coeff*.38));logBattle(b,`${caster.name}は再生を付与。`);break}
 case 'shield':{const val=Math.round((caster.stats.mag+caster.stats.res)*skill.coeff*(.65+(caster.stats.mods?.barrier||0)/100));heroTarget.shield+=val;state.meta.barrier+=val;logBattle(b,`${caster.name}の${skill.name}。${heroTarget.name}に防壁${val}。`);break}
 case 'ward':{let val=0;party.forEach(t=>{const v=Math.round((caster.stats.mag+caster.stats.res)*skill.coeff*.35);t.shield+=v;state.meta.barrier+=v;val+=v});logBattle(b,`${caster.name}は結界を展開。防壁合計${val}。`);break}
 case 'status':{const a=attackAmount(caster,enemyTarget,skill);total=applyDamage(b,caster,enemyTarget,a.amount);const p=Math.round((caster.stats.mag+caster.stats.atk)*skill.coeff*.18*statusPower);addEffect(enemyTarget,skill.status,3,p);state.meta.status++;logBattle(b,`${caster.name}の${skill.name}！ ${enemyTarget.name}へ${total}ダメージと${statusName(skill.status)}。`);break}
 case 'debuff':{const a=attackAmount(caster,enemyTarget,{...skill,coeff:skill.coeff*.55});total=applyDamage(b,caster,enemyTarget,a.amount);addEffect(enemyTarget,skill.status,3,skill.status==='weaken'?.16:0);state.meta.status++;logBattle(b,`${caster.name}は${enemyTarget.name}へ${statusName(skill.status)}を付与。`);break}
 case 'taunt':{addEffect(caster,'taunt',2,0);const tauntBarrier=Math.round(caster.stats.def*skill.coeff*.75);caster.shield+=tauntBarrier;state.meta.barrier+=tauntBarrier;logBattle(b,`${caster.name}は挑発し、防壁を構えた。`);break}
 case 'counter':{addEffect(caster,'counter',2,0);logBattle(b,`${caster.name}は反撃の構え。`);break}
 case 'buff':{party.forEach(t=>addEffect(t,skill.status,2,skill.status==='focus'?.22:0));logBattle(b,`${caster.name}は${skill.name}で味方を強化。`);break}
 case 'cleanse':{party.forEach(t=>{['poison','bleed','burn','freeze','shock','weaken','silence'].forEach(k=>delete t.effects[k]);applyHeal(b,t,caster.stats.mag*skill.coeff*.55)});logBattle(b,`${caster.name}は味方を浄化した。`);break}
 case 'dispel':{enemies.forEach(t=>{t.shield=0;['haste','focus','regen'].forEach(k=>delete t.effects[k])});logBattle(b,`${caster.name}は敵の強化と防壁を解除。`);break}
 case 'summon':{addEffect(caster,'summon',3,Math.round(caster.stats.mag*skill.coeff*.65));logBattle(b,`${caster.name}は使い魔を召喚。`);break}
 case 'drain':{const a=attackAmount(caster,enemyTarget,skill);total=applyDamage(b,caster,enemyTarget,a.amount);const h=applyHeal(b,caster,total*.42);logBattle(b,`${caster.name}は${enemyTarget.name}から${total}吸い、${h}回復。`);break}
 case 'prism':{const white=b.party.find(u=>u.heroId==='hakurei'),black=b.party.find(u=>u.heroId==='kokurei');const count=[white,black,caster].filter(unitAlive).length;party.forEach(t=>{t.shield+=Math.round(caster.stats.mag*skill.coeff*.28*count);addEffect(t,'haste',2,.1)});logBattle(b,`${caster.name}が白・黒・虹を調律。連携${count}段階。`);break}
 default: logBattle(b,`${caster.name}は${skill.name}を使った。`)
 }
 applyBaseSkillEffect(b,caster,skill,enemyTarget,party);if(skill.kind==='magic'||['heal','shield','support'].includes(skill.kind))playSfx('magic');else playSfx('hit');return true}
function applyBaseSkillEffect(b,caster,skill,enemyTarget,party){if(caster.type!=='hero')return;if(caster.heroId==='kozen'){const color=['heal','shield','ward','cleanse','buff','regen'].includes(skill.type)?'white':['status','debuff','execute','drain'].includes(skill.type)?'black':'rainbow';const st=caster.baseState;if((color==='white'||color==='black')&&st.lastColor&&st.lastColor!==color)st.resonance=Math.min(3,st.resonance+1);else if(color==='rainbow')st.resonance=Math.min(3,st.resonance+1);st.lastColor=color;if(st.resonance>=3){const val=Math.max(8,Math.round(caster.stats.mag*.28));party.forEach(t=>{t.shield+=val;addEffect(t,'haste',2,.08)});if(enemyTarget&&unitAlive(enemyTarget)){const bonus=Math.max(6,Math.round(caster.stats.mag*.36));applyDamage(b,caster,enemyTarget,bonus,{direct:true,label:'虹追撃'});}logBattle(b,`${caster.name}の三彩共鳴が完成。全体防壁と虹追撃！`);st.resonance=0}}else if(caster.heroId==='hakurei'&&['heal','shield','ward','cleanse','regen','buff'].includes(skill.type)){party.forEach(t=>addEffect(t,'creation',2,.08));logBattle(b,'創生の護り：味方に被ダメージ軽減を付与。')}else if(caster.heroId==='kokurei'&&enemyTarget&&unitAlive(enemyTarget)){const afflicted=Object.keys(enemyTarget.effects||{}).some(k=>['poison','bleed','burn','weaken','freeze','shock'].includes(k));if(afflicted){const st=caster.baseState;st.marks=Math.min(3,st.marks+1);const bonus=Math.max(4,Math.round(caster.stats.atk*(.08+st.marks*.04)));applyDamage(b,caster,enemyTarget,bonus,{direct:true,label:'終焉追撃'});if(enemyTarget.hp/enemyTarget.maxHp<.35){const exec=Math.max(5,Math.round(caster.stats.atk*.34));applyDamage(b,caster,enemyTarget,exec,{direct:true,label:'処刑'});}logBattle(b,`終焉刻印 ${st.marks}/3：追撃が発動。`)}}}
function cooldownTick(u){Object.entries(u.cooldowns||{}).forEach(([k,v])=>{u.cooldowns[k]=v-1;if(u.cooldowns[k]<=0)delete u.cooldowns[k]})}
function heroTurn(b,skillId,auto=false){if(b.result)return;const u=b.party[b.currentHero];if(!u||!unitAlive(u)){advanceHero(b);return}if(tickEffects(b,u)){advanceHero(b);return}const h=state.heroes[u.heroId];const choices=h.skills.map(getSkill).filter(s=>u.mp>=s.mp&&!u.cooldowns[s.id]);let skill=skillId?getSkill(skillId):autoChooseSkill(b,u,choices);if(!skill||!choices.some(s=>s.id===skill.id)){skill={id:'basic',name:'通常攻撃',type:'damage',kind:'physical',element:'無',coeff:.8,mp:0,cd:0,tags:['物理']}}resolveSkill(b,u,skill);cooldownTick(u);afterAction(b,'hero')}
function autoChooseSkill(b,u,choices){const party=liveParty(b), enemies=liveEnemies(b);const low=chooseLowest(party);if(low&&low.hp/low.maxHp<.44){const heal=choices.find(s=>['heal','cleanse','shield','ward'].includes(s.type));if(heal)return heal}if(enemies.length>1){const aoe=choices.find(s=>s.type==='aoe');if(aoe)return aoe}const status=choices.find(s=>s.type==='status'&&!Object.values(liveEnemies(b)[0]?.effects||{}).some(x=>x.turns>0));if(status)return status;return choices.sort((a,b)=>b.coeff-a.coeff)[0]}
function afterAction(b,side){if(liveEnemies(b).length===0){finishBattle(b,'勝利');return}if(liveParty(b).length===0){finishBattle(b,'敗北');return}if(side==='hero'){advanceHero(b)}else{b.phase='player';b.currentHero=0;b.round++}}
function advanceHero(b){let next=b.currentHero+1;while(next<b.party.length&&!unitAlive(b.party[next]))next++;if(next<b.party.length){b.currentHero=next;b.phase='player';if(b.auto)setTimeout(()=>autoBattleStep(),170)}else{b.phase='enemy';setTimeout(()=>enemyPhase(),b.auto?120:350)}}
function enemyPhase(){const b=state.battle;if(!b||b.result)return;for(const e of b.enemies){if(!unitAlive(e))continue;if(tickEffects(b,e))continue;enemyAction(b,e);cooldownTick(e);if(liveParty(b).length===0){finishBattle(b,'敗北');return}}afterAction(b,'enemy');render();if(b.auto&&!b.result)setTimeout(()=>autoBattleStep(),220)}
function enemyAction(b,e){const heroes=liveParty(b);let target=heroes.find(x=>x.effects.taunt)||chooseLowest(heroes);const role=e.role; if(role==='回復'&&e.hp/e.maxHp<.55){const h=applyHeal(b,e,e.stats.mag*1.2);logBattle(b,`${e.name}は身を癒し${h}回復。`);return}if(role==='防壁'){e.shield+=Math.round(e.stats.res*.8+12);logBattle(b,`${e.name}は防壁を張った。`);return}if(role==='高防御'){const dmg=Math.round(e.stats.atk*.8/(1+target.stats.def/120));applyDamage(b,e,target,dmg);addEffect(e,'counter',1,0);logBattle(b,`${e.name}は守りを固めつつ${target.name}を叩いた。`);return}const magic=['火','氷','雷','闇','水'].includes(e.element);let power=(magic?e.stats.mag:e.stats.atk)*(role==='単体高火力'?1.65:role==='連撃'?0.82:1.05)/(1+(magic?target.stats.res:target.stats.def)/110);if(role==='連撃'){for(let i=0;i<2;i++)applyDamage(b,e,target,power*.7);logBattle(b,`${e.name}の連撃！`)}else{const dmg=applyDamage(b,e,target,power);logBattle(b,`${e.name}は${target.name}へ${dmg}ダメージ。`)}if(role==='毒')addEffect(target,'poison',3,Math.max(4,e.stats.mag*.18));if(role==='火傷')addEffect(target,'burn',3,Math.max(5,e.stats.mag*.2));if(role==='出血')addEffect(target,'bleed',3,Math.max(5,e.stats.atk*.18));if(role==='凍結')addEffect(target,'freeze',1,0);if(role==='感電')addEffect(target,'shock',2,0);if(role==='魔法防御低下')addEffect(target,'weaken',2,.12);if(role==='召喚')addEffect(e,'summon',2,e.stats.mag*.5)}
function autoBattleStep(){const b=state.battle;if(!b||b.result||!b.auto)return;if(b.phase==='player')heroTurn(b,null,true);else enemyPhase();render()}
function toggleBattleAuto(){const b=state.battle;if(!b||b.result)return;b.auto=!b.auto;toast(b.auto?'オート戦闘を開始':'オート戦闘を停止');if(b.auto)setTimeout(()=>autoBattleStep(),180);render()}
function battleDefend(){const b=state.battle;if(!b||b.phase!=='player')return;const u=b.party[b.currentHero];const defendBarrier=Math.round(u.stats.def*.9+u.stats.res*.25);u.shield+=defendBarrier;state.meta.barrier+=defendBarrier;u.mp=Math.min(u.maxMp,u.mp+5);logBattle(b,`${u.name}は防御し、防壁を張った。`);advanceHero(b);render()}
function finishBattle(b,result){if(b.result)return;b.result=result;b.auto=false;if(result==='勝利'){playSfx('victory');b.rewards=grantRewards(b.regionId,b.boss);logBattle(b,'勝利！ 報酬を獲得した。')}else{playSfx('defeat');state.meta.kills+=0}saveState();checkUnlocks();render()}
function battleAdvice(b){const r=findRegion(b.regionId);const p=Object.values(state.heroes).map(getHeroStats);const avgRes=p.reduce((a,x)=>a+x.res,0)/p.length;const avgDef=p.reduce((a,x)=>a+x.def,0)/p.length;if(r.danger.includes('毒'))return '毒耐性・浄化技能・回復量を増やしてください。';if(r.danger.includes('火傷')||r.danger.includes('高火力'))return '防壁、物理防御、回復を増やし、先に火力役を倒してください。';if(r.danger.includes('魔法')||avgRes<35)return '魔法防御と解除技能を増やし、魔法役を優先してください。';if(avgDef<35)return '防御または防壁を増やし、守護役に挑発を持たせてください。';return '職業・種族・装備・技能の役割を揃え、危険要素に対する耐性を準備してください。'}
function protectedByAutoRule(inv){const d=EQUIP_MAP[inv.id],l=state.loop;return (l.keepMinLevel&&d.level>=l.keepMinLevel)||(l.keepTypes||[]).includes(d.type)||(l.keepTags||[]).some(t=>d.tags.includes(t))||(l.keepAffixes||[]).includes(d.affix)||inv.locked||inv.favorite||isEquippedUid(inv.uid)||d.rarity==='ユニーク'}
function processAutoDrop(inv){
 const d=EQUIP_MAP[inv.id],l=state.loop;
 if(protectedByAutoRule(inv)){
   if(state.inventory.length>=MAX_INVENTORY)return {action:'full',gold:0,materials:0};
   state.inventory.push(inv);l.autoKept++;return {action:'keep',gold:0,materials:0};
 }
 const rule=l.autoRules?.[d.rarity]||'keep';
 if(rule==='sell'){const gain=saleValue(inv);state.meta.gold+=gain;l.gold+=gain;l.autoSold++;l.autoGold+=gain;return {action:'sell',gold:gain,materials:0};}
 if(rule==='break'){const mats=Math.max(1,Math.floor(d.level/12)+rarityRank(d.rarity));state.meta.materials['鉄片']=(state.meta.materials['鉄片']||0)+mats;l.autoBroken++;l.autoMaterials+=mats;return {action:'break',gold:0,materials:mats};}
 if(state.inventory.length>=MAX_INVENTORY)return {action:'full',gold:0,materials:0};
 state.inventory.push(inv);l.autoKept++;return {action:'keep',gold:0,materials:0};
}
function addDroppedItem(inv,{useAuto=false}={}){if(useAuto)return processAutoDrop(inv);if(state.inventory.length>=MAX_INVENTORY)return {action:'full',gold:0,materials:0};state.inventory.push(inv);return {action:'keep',gold:0,materials:0}}
function grantRewards(regionId,boss=false,{useAuto=false}={}){const r=findRegion(regionId);const gold=rand(18,42)+r.level*10+(boss?60:0),xp=rand(14,28)+r.level*8+(boss?48:0);const matName=regionId==='verdant_steppe'?'草原の繊維':regionId==='ashfall_ridge'?'火山灰晶':regionId==='frostveil_pass'?'氷晶':regionId==='sunken_archive'?'古文書の欠片':'鉄片';const mats=rand(1,3)+(boss?3:0);state.meta.gold+=gold;state.meta.shards+=Math.max(1,Math.round(xp/7));state.meta.materials[matName]=(state.meta.materials[matName]||0)+mats;state.meta.kills+=boss?1:3;state.meta.bosses+=boss?1:0;Object.values(state.heroes).forEach(h=>{h.xp+=xp;while(h.xp>=h.level*90){h.xp-=h.level*90;h.level++;playSfx('level');toast(`${heroDef(h.id).name}がLv${h.level}になった`,'good')}h.jobXp[h.job]=(h.jobXp[h.job]||0)+xp;const before=jobLevel({...h,jobXp:{...h.jobXp,[h.job]:h.jobXp[h.job]-xp}},h.job);const now=jobLevel(h);if(now>before){toast(`${heroDef(h.id).name}の${findJob(h.job).name}がLv${now}に上昇`,'good')}});if(boss){state.unlocks.bosses[regionId]=(state.unlocks.bosses[regionId]||0)+1;state.unlocks.story=Math.max(state.unlocks.story,r.story+1);Object.values(state.heroes).forEach(h=>h.bond=(h.bond||1)+1)}const count=boss?2:Math.random()<.72?1:2,items=[],instances=[],processed=[];for(let i=0;i<count;i++){const item=rollItem(r.level,boss),d=EQUIP_MAP[item.id];const result=addDroppedItem(item,{useAuto});instances.push(item);items.push(d);processed.push({...result,item,d});if(rarityRank(d.rarity)>=2)playSfx('rare')}return {gold,xp,material:`${matName} ×${mats}`,items,instances,processed}}
function rollItem(level,boss=false){const eligible=EQUIPMENT.filter(x=>Math.abs(x.level-level*2)<=18&&x.rarity!=='ユニーク');let d=pick(eligible);const chance=Math.random();if(boss&&chance<.16)d=pick(EQUIPMENT.filter(x=>x.rarity==='ユニーク'));else if(chance<.04)d=pick(eligible.filter(x=>x.rarity==='レジェンダリー'));else if(chance<.12)d=pick(eligible.filter(x=>x.rarity==='エピック'));else if(chance<.32)d=pick(eligible.filter(x=>x.rarity==='レア'));else if(chance<.58)d=pick(eligible.filter(x=>x.rarity==='アンコモン'));return makeItem(d.id)}

function runSimulation(regionId,boss=false){const r=findRegion(regionId);const b={regionId,boss,party:Object.values(state.heroes).map(makeHeroUnit),enemies:(boss?[r.boss]:[pick(r.enemies),pick(r.enemies),pick(r.enemies)]).map(id=>makeEnemyUnit(id,r.level,boss)),log:[],currentHero:0,phase:'player',round:1,result:null,rewards:null};let steps=0;while(!b.result&&steps<110){if(b.phase==='player'){const u=b.party[b.currentHero];if(unitAlive(u)){if(!tickEffects(b,u)){const h=state.heroes[u.heroId];const choices=h.skills.map(getSkill).filter(s=>u.mp>=s.mp&&!u.cooldowns[s.id]);const s=autoChooseSkill(b,u,choices)||{id:'basic',name:'通常攻撃',type:'damage',kind:'physical',element:'無',coeff:.8,mp:0,cd:0,tags:['物理']};resolveSkill(b,u,s);cooldownTick(u)}advanceHeroSim(b)}else advanceHeroSim(b)}else{for(const e of b.enemies){if(unitAlive(e)&&!tickEffects(b,e))enemyAction(b,e);if(!liveParty(b).length)break}if(liveParty(b).length===0){b.result='敗北'}else{b.phase='player';b.currentHero=0;b.round++}}if(liveEnemies(b).length===0)b.result='勝利';if(liveParty(b).length===0)b.result='敗北';steps++}if(!b.result)b.result='敗北';return b}
function advanceHeroSim(b){if(liveEnemies(b).length===0){b.result='勝利';return}let next=b.currentHero+1;while(next<b.party.length&&!unitAlive(b.party[next]))next++;if(next<b.party.length){b.currentHero=next;b.phase='player'}else b.phase='enemy'}
function startLoop(){const l=state.loop;if(l.running)return;if(!regionUnlocked(l.regionId)){toast('地域を解放してください','warn');return}l.running=true;l.session++;l.run=0;l.wins=0;l.deaths=0;l.gold=0;l.xp=0;l.drops=[];l.autoKept=0;l.autoSold=0;l.autoBroken=0;l.autoGold=0;l.autoMaterials=0;l.lastStopReason='';l.logs=[`【開始】${findRegion(l.regionId).name}を周回します。自動整理：${RARITY_ORDER.map(r=>`${r}${l.autoRules[r]}`).join(' / ')}`];toast('オート周回を開始','good');loopTimer=setInterval(loopStep,450);render()}
function stopLoop(reason='手動停止'){const l=state.loop;if(!l.running)return;l.running=false;l.lastStopReason=reason;if(loopTimer){clearInterval(loopTimer);loopTimer=null}l.logs.push(`【停止】${reason}`);saveState();render();toast(`周回を停止：${reason}`,'good')}
function loopStep(){const l=state.loop;if(!l.running)return;if(!l.unlimited&&l.run>=Number(l.target||1)){stopLoop('指定回数に到達');return}if(l.stopFull&&state.inventory.length>=MAX_INVENTORY){stopLoop('所持品が10,000件に到達');return}const b=runSimulation(l.regionId,l.boss);l.run++;if(b.result==='勝利'){l.wins++;const rewards=grantRewards(l.regionId,l.boss,{useAuto:true});l.gold+=rewards.gold;l.xp+=rewards.xp;l.drops.push(...rewards.items);const actions=rewards.processed.map(x=>x.action);if(rewards.processed.some(x=>x.action==='full')&&l.stopFull){checkUnlocks();stopLoop('所持品が10,000件に到達（自動整理で保持対象が残りました）');return}l.logs.push(`#${l.run} 勝利　G${rewards.gold} / ${rewards.items.map((i,n)=>`${i.name}${actions[n]==='sell'?'[売却]':actions[n]==='break'?'[分解]':''}`).join('、')}`);if(l.stopRare&&rewards.items.some(i=>rarityRank(i.rarity)>=2)){checkUnlocks();stopLoop('レア以上を獲得');return}if(l.stopItem&&rewards.items.some(i=>i.name.includes(l.stopItem))){checkUnlocks();stopLoop(`指定装備「${l.stopItem}」を獲得`);return}if(l.stopXp&&l.xp>=l.stopXp){checkUnlocks();stopLoop('経験値目標に到達');return}if(l.stopMaterial&&l.stopMaterialCount&&(state.meta.materials[l.stopMaterial]||0)>=l.stopMaterialCount){checkUnlocks();stopLoop(`${l.stopMaterial}の目標数に到達`);return}const hpRatio=Math.min(...b.party.map(u=>u.hp/u.maxHp))*100,mpRatio=Math.min(...b.party.map(u=>u.mp/u.maxMp))*100;if(l.stopHp&&hpRatio<l.stopHp){checkUnlocks();stopLoop(`終了HP条件（${Math.floor(hpRatio)}%）`);return}if(l.stopMp&&mpRatio<l.stopMp){checkUnlocks();stopLoop(`終了MP条件（${Math.floor(mpRatio)}%）`);return}}else{l.deaths++;l.logs.push(`#${l.run} 戦闘不能　${battleAdvice(b)}`);if(l.stopDeath){checkUnlocks();stopLoop('戦闘不能');return}}if(l.logs.length>60)l.logs.splice(0,l.logs.length-60);checkUnlocks();saveState();if(state.screen==='loop')render()}

function checkUnlocks(){const previous={jobs:new Set(state.unlocks.jobs),races:new Set(state.unlocks.races),regions:new Set(state.unlocks.regions)};REGIONS.forEach(r=>{if(r.story<=state.unlocks.story&&!regionUnlocked(r.id))state.unlocks.regions.push(r.id)});JOBS.forEach(j=>{if(jobUnlocked(j.id))return;let ok=false;if(j.tier==='normal')ok=state.unlocks.story>=j.requiresStory;else if(j.requiresJobs.length)ok=j.requiresJobs.every(id=>maxJobLevel(id)>=10);if(ok){state.unlocks.jobs.push(j.id);toast(`${j.name}が解放された！`,'good');playSfx('unlock')}});const raceRules={dwarf:()=>state.meta.forge>=5,beastfolk:()=>isBossCleared('verdant_steppe'),catfolk:()=>state.meta.kills>=40,wolfkin:()=>maxJobLevel('hunter')>=10,dragonkin:()=>regionUnlocked('stormcrown_spire'),lizardman:()=>isBossCleared('sunscar_dunes'),angel:()=>state.heroes.hakurei.bond>=5,fallen:()=>state.heroes.kokurei.bond>=5,demon:()=>state.meta.status>=100,vampire:()=>false,goblin:()=>Object.values(state.meta.materials).reduce((a,b)=>a+b,0)>=500,orc:()=>state.meta.barrier>=10000,giant:()=>state.meta.kills>=300,fairy:()=>state.meta.status>=30,elemental:()=>state.meta.kills>=50,undead:()=>state.loop.deaths>=10,automaton:()=>isBossCleared('stormcrown_spire')};RACES.forEach(r=>{if(!raceUnlocked(r.id)&&raceRules[r.id]?.()){state.unlocks.races.push(r.id);toast(`${r.name}が解放された！`,'good');playSfx('unlock')}});QUESTS.forEach(q=>{if(state.unlocks.quests.includes(q.id))return;let ok=false;if(q.goal.startsWith('boss:'))ok=isBossCleared(q.goal.split(':')[1]);else if(q.goal.startsWith('forge:'))ok=state.meta.forge>=+q.goal.split(':')[1];else if(q.goal.startsWith('status:'))ok=state.meta.status>=+q.goal.split(':')[1];else if(q.goal.startsWith('barrier:'))ok=state.meta.barrier>=+q.goal.split(':')[1];else if(q.goal.startsWith('kills:'))ok=state.meta.kills>=+q.goal.split(':')[1];else if(q.goal.startsWith('region:'))ok=regionUnlocked(q.goal.split(':')[1]);if(ok){state.unlocks.quests.push(q.id);toast(`依頼達成：${q.name}`,'good')}});saveState()}

function esc(s){return String(s||'').replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]))}
function pickHero(id){state.ui.selectedHero=id;saveState();render()}
function chooseRace(heroId){const h=state.heroes[heroId];modal('種族を選択',`<div class="race-grid">${RACES.map(r=>`<button class="race-card ${raceUnlocked(r.id)?'':'locked'} ${h.race===r.id?'active':''}" data-act="set-race" data-hero="${heroId}" data-id="${r.id}" ${raceUnlocked(r.id)?'':'disabled'}><b>${r.name}</b><p>${raceUnlocked(r.id)?r.flavor:`解放条件：${r.unlock}`}</p><div class="race-stat">${r.passive}</div></button>`).join('')}</div>`,{wide:true})}
function chooseJob(heroId){const h=state.heroes[heroId];modal('職業を選択',`<div class="job-tree">${['normal','advanced','transcend'].map(t=>`<div class="job-tier"><h3>${t==='normal'?'通常職':t==='advanced'?'上級職':'超級職'}</h3><div class="job-grid">${JOBS.filter(j=>j.tier===t).map(j=>`<button class="job-card ${jobUnlocked(j.id)?'':'locked'} ${h.job===j.id?'active':''}" data-act="set-job" data-hero="${heroId}" data-id="${j.id}" ${jobUnlocked(j.id)?'':'disabled'}><div class="job-name">${j.name}</div><div class="job-desc">${j.desc}</div><div class="job-level">${jobUnlocked(j.id)?`最高Lv${maxJobLevel(j.id)}`:`${j.requiresJobs.map(id=>findJob(id).name).join('＋')}が必要`}</div></button>`).join('')}</div></div>`).join('')}</div>`,{wide:true})}
function chooseSkills(heroId,page=0,slot=state.ui.modalSkillSlot||0){
 const h=state.heroes[heroId]; const skills=SKILLS.filter(s=>skillKnown(s.id)); const per=36; const max=Math.max(0,Math.ceil(skills.length/per)-1); const current=clamp(Number(page)||0,0,max); const selected=clamp(Number(slot)||0,0,3);
 state.ui.modalSkillsPage=current; state.ui.modalSkillSlot=selected;
 const equipped=`<div class="skill-slot-row">${h.skills.map((id,i)=>{const sk=getSkill(id);return `<button class="skill-slot ${i===selected?'active':''}" data-act="modal-skill-slot" data-hero="${heroId}" data-id="${i}"><small>枠${i+1}</small><b>${sk.name}</b><span>${sk.element} / MP${sk.mp}</span></button>`}).join('')}</div>`;
 const cards=skills.slice(current*per,current*per+per).map(s=>`<button class="skill-card ${h.skills.includes(s.id)?'learned':''}" data-act="modal-equip-skill" data-hero="${heroId}" data-id="${s.id}"><b>${s.name}</b><p>${s.desc}</p><div class="skill-meta">${tagHtml([s.element,...s.tags.slice(0,2)])}</div></button>`).join('');
 const pager=`<div class="pager"><button class="btn ghost tiny-btn" data-act="modal-skill-page" data-hero="${heroId}" data-id="-1" ${current===0?'disabled':''}>前へ</button><span>${current+1} / ${max+1} ページ　${skills.length}件</span><button class="btn ghost tiny-btn" data-act="modal-skill-page" data-hero="${heroId}" data-id="1" ${current===max?'disabled':''}>次へ</button></div>`;
 modal('技能を編集',`<p class="page-lead">${heroDef(heroId).name}の4枠を編集します。先に置き換える枠を選び、下の習得済み技能を押してください。</p>${equipped}${pager}<div class="skill-grid">${cards||'<div class="empty">習得済み技能がありません。</div>'}</div>${pager}`,{wide:true});
}
function equipSkill(heroId,skillId,slot=state.ui.modalSkillSlot||0){const h=state.heroes[heroId];if(h.skills.includes(skillId)){toast('すでに装備しています','warn');return}h.skills[clamp(Number(slot)||0,0,3)]=skillId;saveState();render();closeModal();toast('技能を装備しました','good')}
function heroDetail(id){const h=state.heroes[id],s=getHeroStats(h);modal(`${heroDef(id).name}のビルド詳細`, `<div class="modal-grid"><div><img class="modal-art" src="${ASSET.hero(id,'victory')}"><h3>${findJob(h.job).name} Lv${jobLevel(h)}</h3><p class="small">${buildDirection(h)}</p></div><div><dl class="kv"><dt>種族</dt><dd>${raceDef(h.race).name}</dd><dt>職業パッシブ</dt><dd>${findJob(h.job).passive}</dd><dt>種族パッシブ</dt><dd>${raceDef(h.race).passive}</dd><dt>基本性能</dt><dd>${statText(s)}</dd></dl></div></div><div class="modal-actions"><button class="btn primary" data-act="choose-race" data-id="${id}">種族変更</button><button class="btn primary" data-act="choose-job" data-id="${id}">職業変更</button><button class="btn secondary" data-act="choose-skills" data-id="${id}">技能編集</button></div>`)}
function regionDetail(id){const r=findRegion(id),power=Math.round(r.level*260+400);modal(r.name,`<div class="modal-grid"><div><img class="modal-art" style="width:100%;height:auto" src="${ASSET.region(r.bg)}"><p class="page-lead">${r.desc}</p><div class="tag-row">${tagHtml(r.tags)}</div></div><div><dl class="kv"><dt>推奨戦力</dt><dd>${fmt(power)}</dd><dt>危険要素</dt><dd>${r.danger}</dd><dt>推奨対策</dt><dd>${r.resist}</dd><dt>主要ドロップ</dt><dd>${r.reward}</dd><dt>周回目安</dt><dd>${r.time}</dd><dt>ボス</dt><dd>${findEnemy(r.boss).name}</dd></dl></div></div><div class="modal-actions"><button class="btn primary" data-act="start-battle" data-id="${id}">通常探索</button><button class="btn warn" data-act="start-boss" data-id="${id}">ボスへ挑戦</button><button class="btn secondary" data-act="set-loop-region" data-id="${id}">この地域を周回設定</button></div>`)}
function itemDetail(uid){const inv=invItem(uid),d=inv&&EQUIP_MAP[inv.id];if(!d)return;const h=state.heroes[state.ui.selectedHero],equippedUid=h.equip?.[d.type],equipped=equippedUid?itemDefFromUid(equippedUid):null;modal(d.name,`<div class="modal-grid"><div><img class="modal-art" src="${ASSET.icon(d.icon)}"><p class="${rarityClass(d.rarity)}"><b>${d.rarity}　Lv帯${d.level}</b></p><p class="small">${d.desc}</p><div class="tag-row">${tagHtml([d.typeLabel,...d.tags])}</div></div><div><dl class="kv"><dt>現在の性能</dt><dd>${statLine(d.stats)}</dd><dt>強化段階</dt><dd>+${inv.upgrade||0}</dd><dt>セット</dt><dd>${d.set}</dd><dt>入手先</dt><dd>${d.source}</dd><dt>比較対象</dt><dd>${equipped?`${equipped.name}<br>${statLine(equipped.stats)}`:'この部位は未装備'}</dd></dl></div></div><div class="modal-actions"><button class="btn primary" data-act="equip-item" data-id="${uid}">選択中の${heroDef(h.id).name}に装備</button><button class="btn secondary" data-act="forge" data-id="${uid}">強化する</button><button class="btn ghost" data-act="toggle-lock" data-id="${uid}">${inv.locked?'保護を外す':'保護する'}</button>${!equippedUid||equippedUid!==uid?`<button class="btn warn" data-act="sell-item" data-id="${uid}" ${inv.locked?'disabled':''}>売却</button>`:''}<button class="btn ghost" data-act="toggle-favorite" data-id="${uid}">${inv.favorite?'お気に入り解除':'お気に入り'}</button><button class="btn ghost" data-act="toggle-junk" data-id="${uid}">${inv.junk?'ジャンク解除':'ジャンク指定'}</button></div>`)}
function equipItem(uid){const inv=invItem(uid),d=inv&&EQUIP_MAP[inv.id],h=state.heroes[state.ui.selectedHero];if(!d||!h)return;h.equip[d.type]=uid;saveState();closeModal();render();toast(`${d.name}を装備しました`,'good')}
function catalogDetail(id){
  const d=EQUIP_MAP[id]; if(!d)return;
  modal(d.name,`<div class="modal-grid"><div><img class="modal-art" src="${ASSET.icon(d.icon)}"><p class="${rarityClass(d.rarity)}"><b>${d.rarity}　Lv帯${d.level}</b></p><p class="small">${d.desc}</p></div><div><dl class="kv"><dt>カテゴリ</dt><dd>${d.typeLabel}</dd><dt>基礎性能</dt><dd>${statLine(d.stats)}</dd><dt>セット</dt><dd>${d.set}</dd><dt>入手先</dt><dd>${d.source}</dd><dt>推奨ビルド</dt><dd>${d.tags.join('・')}</dd></dl></div></div>`);
}
function slotDetail(type){
  const h=state.heroes[state.ui.selectedHero];
  const matches=state.inventory.filter(i=>EQUIP_MAP[i.id]?.type===type);
  const title=`${EQUIPMENT.find(x=>x.type===type)?.typeLabel||type}を選択`;
  const body=matches.length
    ? `<div class="table-wrap"><table class="data-table"><thead><tr><th>装備</th><th>性能</th><th></th></tr></thead><tbody>${matches.map(i=>{const d=EQUIP_MAP[i.id];return `<tr><td><img class="item-icon" src="${ASSET.icon(d.icon)}"><b class="${rarityClass(d.rarity)}">${d.name}</b></td><td>${statLine(d.stats)}<br><small>${d.desc}</small></td><td><button class="btn primary tiny-btn" data-act="equip-item" data-id="${i.uid}">装備</button></td></tr>`}).join('')}</tbody></table></div>`
    : `<div class="empty">このカテゴリの装備を所持していません。</div>`;
  modal(title,body,{wide:true});
}
function forge(uid){const inv=invItem(uid),d=inv&&EQUIP_MAP[inv.id];if(!inv||!d)return;const lv=inv.upgrade||0,cost=2+lv*2,gold=35+lv*20;if(lv>=10){toast('すでに最大まで強化されています','warn');return}if((state.meta.materials['鉄片']||0)<cost||state.meta.gold<gold){toast(`素材不足：鉄片${cost} / G${gold}が必要です`,'warn');return}state.meta.materials['鉄片']-=cost;state.meta.gold-=gold;inv.upgrade=lv+1;state.meta.forge++;checkUnlocks();saveState();playSfx('level');closeModal();render();toast(`${d.name}を+${inv.upgrade}へ強化`,'good')}
function sellItem(uid){const inv=invItem(uid),d=inv&&EQUIP_MAP[inv.id];if(!inv||!d)return;if(inv.locked){toast('保護中の装備は売却できません','warn');return}const used=Object.values(state.heroes).some(h=>Object.values(h.equip||{}).includes(uid));if(used){toast('装備中の品は外してから売却してください','warn');return}state.meta.gold+=Math.max(15,d.level*8+d.stars*25+(inv.upgrade||0)*15);state.inventory=state.inventory.filter(i=>i.uid!==uid);saveState();closeModal();render();toast(`${d.name}を売却しました`,'good')}
function toggleLock(uid){const inv=invItem(uid);if(!inv)return;inv.locked=!inv.locked;saveState();closeModal();render();toast(inv.locked?'装備を保護しました':'装備保護を外しました')}
function learnSkill(id){const s=getSkill(id),h=state.heroes[state.ui.selectedHero],cost=s.rank*4;if(skillKnown(id)){toast('すでに習得済みです','warn');return}if(jobLevel(h)<s.rank*2){toast(`職業Lv${s.rank*2}が必要です`,'warn');return}if(state.meta.shards<cost){toast('魂片が足りません','warn');return}state.meta.shards-=cost;state.unlocks.skills.push(id);saveState();playSfx('unlock');render();toast(`${s.name}を習得しました`,'good')}
function jobDetail(id){const j=findJob(id),req=j.requiresJobs.length?j.requiresJobs.map(x=>`${findJob(x).name} Lv${maxJobLevel(x)}/10`).join(' ＋ '):j.tier==='normal'?`物語段階 ${j.requiresStory}`:'特別依頼';modal(j.name,`<div class="modal-grid"><div><h3>${j.tier==='normal'?'通常職':j.tier==='advanced'?'上級職':'超級職'}</h3><p class="page-lead">${j.desc}</p><div class="tag-row">${tagHtml([j.tag,j.weapon,j.armor])}</div></div><div><dl class="kv"><dt>得意武器</dt><dd>${j.weapon}</dd><dt>得意防具</dt><dd>${j.armor}</dd><dt>固有パッシブ</dt><dd>${j.passive}</dd><dt>基礎補正</dt><dd>${statLine(j.bonus)}</dd><dt>解放条件</dt><dd>${jobUnlocked(j.id)?'解放済み':req}</dd><dt>次の到達先</dt><dd>${j.next.length?j.next.map(x=>findJob(x).name).join('、'):'—'}</dd></dl></div></div><div class="modal-actions">${jobUnlocked(j.id)?Object.values(state.heroes).map(h=>`<button class="btn primary" data-act="set-job" data-hero="${h.id}" data-id="${j.id}">${heroDef(h.id).name}へ設定</button>`).join(''):''}</div>`)}
function raceDetail(id){const r=raceDef(id);modal(r.name,`<div class="modal-grid"><div><h3>${r.name}</h3><p class="page-lead">${r.flavor}</p><p class="green">${r.passive}</p></div><div><dl class="kv"><dt>向くビルド</dt><dd>${r.good}</dd><dt>苦手なビルド</dt><dd>${r.weak}</dd><dt>基礎補正</dt><dd>${statLine(r.bonus)}</dd><dt>解放条件</dt><dd>${raceUnlocked(r.id)?'解放済み':r.unlock}</dd></dl></div></div><div class="modal-actions">${raceUnlocked(r.id)?Object.values(state.heroes).map(h=>`<button class="btn primary" data-act="set-race" data-hero="${h.id}" data-id="${r.id}">${heroDef(h.id).name}へ設定</button>`).join(''):''}</div>`)}
function skillDetail(id){const s=getSkill(id);modal(s.name,`<dl class="kv"><dt>効果</dt><dd>${s.desc}</dd><dt>属性</dt><dd>${s.element}</dd><dt>分類</dt><dd>${s.tags.join('・')}</dd><dt>威力/効果量</dt><dd>${s.coeff}</dd><dt>消費MP</dt><dd>${s.mp}</dd><dt>クールダウン</dt><dd>${s.cd}</dd><dt>習得条件</dt><dd>${s.unlock}</dd></dl><div class="modal-actions">${skillKnown(s.id)?`<button class="btn primary" data-act="equip-skill" data-id="${s.id}">選択中の英雄に装備</button>`:`<button class="btn good" data-act="learn-skill" data-id="${s.id}">習得する</button>`}</div>`)}
function jobGuide(){modal('職業解放の見方',`<div class="card-soft"><b>通常職</b><p class="small">物語・地域・依頼を進めると増えます。</p></div><div class="card-soft" style="margin-top:10px"><b>上級職</b><p class="small">特定の通常職を2つLv10にすることで解放されます。職業カードには、現在の最高Lvと必要条件が表示されます。</p></div><div class="card-soft" style="margin-top:10px"><b>超級職</b><p class="small">特定の上級職を3つLv10にするか、高難度の進行条件を満たすことで解放されます。</p></div>`)}
function setJob(heroId,id){if(!jobUnlocked(id)){toast('この職業はまだ解放されていません','warn');return}const h=state.heroes[heroId];h.job=id;h.jobXp[id]??=0;saveState();closeModal();render();toast(`${heroDef(heroId).name}を${findJob(id).name}へ転職`,'good')}
function setRace(heroId,id){if(!raceUnlocked(id)){toast('この種族はまだ解放されていません','warn');return}state.heroes[heroId].race=id;saveState();closeModal();render();toast(`${heroDef(heroId).name}の種族を${raceDef(id).name}へ変更`,'good')}
function importSave(){modal('セーブデータを読み込む',`<p class="page-lead">書き出したJSONファイルを選択してください。壊れたデータは読み込みません。</p><input class="input" type="file" accept="application/json" data-import-file><div class="modal-actions"><button class="btn primary" data-act="do-import">読み込む</button><button class="btn ghost" data-act="close-modal">キャンセル</button></div>`)}
function doImport(){const file=$('[data-import-file]')?.files?.[0];if(!file){toast('ファイルを選択してください','warn');return}const reader=new FileReader();reader.onload=()=>{try{state=normalizeState(JSON.parse(reader.result));clearTimers();saveState();closeModal();render();toast('セーブデータを読み込みました','good')}catch(e){toast('セーブデータが壊れているか、形式が違います','warn')}};reader.readAsText(file)}
function exportSave(){const blob=new Blob([JSON.stringify(state,null,2)],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`omnil-save-${new Date().toISOString().slice(0,10)}.json`;a.click();URL.revokeObjectURL(a.href);toast('セーブデータを書き出しました','good')}

function setLoopRegion(id){state.loop.regionId=id;state.screen='loop';saveState();closeModal();render();toast('周回地域を設定しました','good')}
function applyAutoSell(){return true}

function getSelectedItems(){const set=new Set(state.ui.inventorySelected||[]);return state.inventory.filter(i=>set.has(i.uid))}
function setSelected(uids){state.ui.inventorySelected=[...new Set(uids)].filter(uid=>invItem(uid)).slice(0,MAX_INVENTORY)}
function selectVisiblePage(){const view=inventoryView(),p=clamp(state.ui.inventoryPage||0,0,Math.max(0,Math.ceil(view.length/INVENTORY_PAGE_SIZE)-1));setSelected([...(state.ui.inventorySelected||[]),...view.slice(p*INVENTORY_PAGE_SIZE,p*INVENTORY_PAGE_SIZE+INVENTORY_PAGE_SIZE).map(i=>i.uid)]);saveState();render()}
function selectFiltered(){setSelected([...(state.ui.inventorySelected||[]),...inventoryView().map(i=>i.uid)]);saveState();render()}
function invertSelection(){const existing=new Set(state.ui.inventorySelected||[]);setSelected(inventoryView().filter(i=>!existing.has(i.uid)).map(i=>i.uid));saveState();render()}
function bulkPreview(action,items){const eligible=items.filter(i=>['lock','unlock','favorite','unfavorite','junk','unjunk'].includes(action)||isBulkEligible(i));const omitted=items.length-eligible.length;const gold=action==='sell'?eligible.reduce((n,i)=>n+saleValue(i),0):0;const mats=action==='break'?eligible.reduce((n,i)=>n+Math.max(1,Math.floor(EQUIP_MAP[i.id].level/12)+rarityRank(EQUIP_MAP[i.id].rarity)),0):0;return {eligible,omitted,gold,mats}}
function confirmBulk(action,source='selection'){const items=source==='selection'?getSelectedItems():[];if(!items.length){toast('対象の装備を選択してください','warn');return}const p=bulkPreview(action,items);const names={sell:'一括売却',break:'一括分解',lock:'一括保護',unlock:'一括保護解除',favorite:'一括お気に入り',unfavorite:'一括お気に入り解除',junk:'一括ジャンク指定',unjunk:'一括ジャンク解除'};modal(names[action],`<div class="card-soft"><b>対象：${fmt(p.eligible.length)}件</b><p class="small">${p.omitted?`除外：${fmt(p.omitted)}件（装備中・保護中・お気に入り・ユニークの安全設定）<br>`:''}${action==='sell'?`売却予定額：<b>${fmt(p.gold)} Gold</b>`:''}${action==='break'?`分解予定：<b>鉄片 ${fmt(p.mats)}</b>`:''}${['lock','unlock','favorite','unfavorite','junk','unjunk'].includes(action)?'状態を一括変更します。':''}</p></div><p class="tiny muted">実行後は元に戻せません。対象と除外条件を確認してください。</p><div class="modal-actions"><button class="btn ${action==='sell'?'warn':'primary'}" data-act="bulk-execute" data-id="${action}">${names[action]}を実行</button><button class="btn ghost" data-act="close-modal">キャンセル</button></div>`)}
function executeBulk(action){if(state.ui.bulkBusy)return;state.ui.bulkBusy=true;try{const items=getSelectedItems(),p=bulkPreview(action,items);if(!p.eligible.length){toast('安全設定により処理対象がありません','warn');return}const ids=new Set(p.eligible.map(i=>i.uid));if(action==='sell'){state.meta.gold+=p.gold;state.inventory=state.inventory.filter(i=>!ids.has(i.uid))}else if(action==='break'){state.meta.materials['鉄片']=(state.meta.materials['鉄片']||0)+p.mats;state.inventory=state.inventory.filter(i=>!ids.has(i.uid))}else{state.inventory.forEach(i=>{if(ids.has(i.uid)){if(action==='lock')i.locked=true;if(action==='unlock')i.locked=false;if(action==='favorite')i.favorite=true;if(action==='unfavorite')i.favorite=false;if(action==='junk')i.junk=true;if(action==='unjunk')i.junk=false}})}setSelected((state.ui.inventorySelected||[]).filter(uid=>!ids.has(uid)));state.ui.bulkBusy=false;saveState();closeModal();render();toast(`${p.eligible.length}件を${action==='sell'?'売却':action==='break'?'分解':'更新'}しました`,'good')}finally{state.ui.bulkBusy=false}}
function confirmRarityBulk(value){const [action,rarity]=value.split('|');const target=state.inventory.filter(i=>EQUIP_MAP[i.id]?.rarity===rarity);setSelected(target.map(i=>i.uid));saveState();confirmBulk(action)}
function toggleFavorite(uid){const i=invItem(uid);if(!i)return;i.favorite=!i.favorite;saveState();render();toast(i.favorite?'お気に入りに登録':'お気に入りを解除','good')}
function toggleJunk(uid){const i=invItem(uid);if(!i)return;i.junk=!i.junk;saveState();render();toast(i.junk?'ジャンクに指定':'ジャンク指定を解除','good')}
function openAutoRules(){const l=state.loop,types=[...new Set(EQUIPMENT.map(e=>e.type))],affixes=[...new Set(EQUIPMENT.map(e=>e.affix))],tags=[...new Set(EQUIPMENT.flatMap(e=>e.tags).filter(x=>x!=='unique'))];modal('周回の自動整理',`<p class="page-lead">レアリティごとの処理に加え、保持条件に一致する装備は必ず残します。ユニークは常に保持です。</p><div class="auto-rules">${RARITY_ORDER.map(r=>`<label class="field"><span>${r}</span><select class="select" data-auto-rule="${r}" ${r==='ユニーク'?'disabled':''}><option value="keep" ${l.autoRules[r]==='keep'?'selected':''}>保持</option><option value="sell" ${l.autoRules[r]==='sell'?'selected':''}>自動売却</option><option value="break" ${l.autoRules[r]==='break'?'selected':''}>自動分解</option></select></label>`).join('')}</div><div class="grid-2" style="margin-top:12px"><label class="field"><span>保持するカテゴリ</span><select class="select" multiple data-auto-list="keepTypes">${types.map(t=>`<option value="${t}" ${l.keepTypes.includes(t)?'selected':''}>${EQUIPMENT.find(e=>e.type===t).typeLabel}</option>`).join('')}</select></label><label class="field"><span>保持するタグ</span><select class="select" multiple data-auto-list="keepTags">${tags.map(t=>`<option value="${t}" ${l.keepTags.includes(t)?'selected':''}>${t}</option>`).join('')}</select></label><label class="field"><span>保持する効果</span><select class="select" multiple data-auto-list="keepAffixes">${affixes.map(t=>`<option value="${t}" ${l.keepAffixes.includes(t)?'selected':''}>${t}</option>`).join('')}</select></label><label class="field"><span>装備Lv以上を保持</span><input class="input" type="number" min="0" data-auto-number="keepMinLevel" value="${l.keepMinLevel||0}"></label></div><div class="modal-actions"><button class="btn primary" data-act="save-auto-rules">設定を保存</button><button class="btn ghost" data-act="close-modal">キャンセル</button></div>`,{wide:true})}
function saveAutoRules(){const l=state.loop;$$('[data-auto-rule]').forEach(el=>{l.autoRules[el.dataset.autoRule]=el.value});$$('[data-auto-list]').forEach(el=>{l[el.dataset.autoList]=[...el.selectedOptions].map(o=>o.value)});const n=$('[data-auto-number="keepMinLevel"]');l.keepMinLevel=Math.max(0,Number(n?.value)||0);l.autoRules['ユニーク']='keep';saveState();closeModal();render();toast('自動整理設定を保存しました','good')}
function handleAction(act,el){initAudio();if(act!=='modal-backdrop'&&act!=='close-modal')playSfx('click');const id=el.dataset.id;switch(act){
 case 'start-game': state.flags.seenTitle=true;state.screen='home';saveState();render();break;
 case 'title-settings': state.flags.seenTitle=true;state.screen='settings';saveState();render();break;
 case 'toggle-nav': $('.nav')?.scrollIntoView({behavior:'smooth'});break;
 case 'nav': state.screen=id;saveState();render();break;case 'home':state.screen='home';saveState();render();break;
 case 'save':saveState(false);break;case 'export':exportSave();break;case 'import':importSave();break;case 'do-import':doImport();break;
 case 'confirm-reset':confirmModal('最初から始める','現在のローカルセーブを上書きします。書き出しを済ませましたか？','do-reset','最初から始める');break;case 'do-reset':closeModal();resetState();break;
 case 'close-modal':closeModal();break;case 'modal-backdrop':if(el.classList.contains('modal-backdrop'))closeModal();break;
 case 'select-hero':pickHero(id);break;case 'select-inventory-hero':state.ui.selectedHero=id;saveState();closeModal();render();toast(`${heroDef(id).name}を装備対象にしました`,'good');break;case 'hero-detail':heroDetail(id);break;
 case 'region-detail':regionDetail(id);break;case 'quick-battle':startBattle(id,false);break;case 'start-battle':closeModal();startBattle(id,false);break;case 'start-boss':closeModal();startBattle(id,true);break;case 'set-loop-region':setLoopRegion(id);break;
 case 'choose-race':chooseRace(id||state.ui.selectedHero);break;case 'choose-job':chooseJob(id||state.ui.selectedHero);break;case 'choose-skills':chooseSkills(id||state.ui.selectedHero);break;
 case 'set-race':setRace(el.dataset.hero,id);break;case 'set-job':setJob(el.dataset.hero,id);break;case 'modal-skill-slot':chooseSkills(el.dataset.hero,state.ui.modalSkillsPage||0,Number(id));break;case 'modal-skill-page':chooseSkills(el.dataset.hero,(state.ui.modalSkillsPage||0)+Number(id),state.ui.modalSkillSlot||0);break;case 'modal-equip-skill':equipSkill(el.dataset.hero,id,state.ui.modalSkillSlot||0);break;case 'equip-skill':equipSkill(state.ui.selectedHero,id,0);break;
 case 'job-detail':jobDetail(id);break;case 'job-guide':jobGuide();break;case 'race-detail':raceDetail(id);break;
 case 'learn-skill':learnSkill(id);break;case 'skill-detail':skillDetail(id);break;
 case 'slot-detail':slotDetail(id);break;case 'item-detail':itemDetail(id);break;case 'equip-item':equipItem(id);break;case 'forge':forge(id);break;case 'sell-item':sellItem(id);break;case 'toggle-lock':toggleLock(id);break;case 'toggle-favorite':toggleFavorite(id);break;case 'toggle-junk':toggleJunk(id);break;case 'choose-hero-inventory':chooseHeroForInventory();break;case 'select-page':selectVisiblePage();break;case 'select-filtered':selectFiltered();break;case 'invert-selection':invertSelection();break;case 'clear-selection':setSelected([]);saveState();render();break;case 'bulk-confirm':confirmBulk(id);break;case 'bulk-execute':executeBulk(id);break;case 'bulk-rarity-confirm':confirmRarityBulk(id);break;case 'open-auto-rules':openAutoRules();break;case 'save-auto-rules':saveAutoRules();break;case 'inventory-page':state.ui.inventoryPage=Math.max(0,(state.ui.inventoryPage||0)+Number(id));saveState();render();break;case 'inventory-reset-filters':Object.assign(state.ui,{inventoryFilter:'',inventoryType:'all',inventoryRarity:'all',inventoryTag:'all',inventoryMinLevel:0,inventoryMaxLevel:0,inventorySort:'newest',inventoryPage:0});saveState();render();break;
 case 'apply-inventory-filter':applyFilters();break;case 'apply-skill-filter':state.ui.skillsPage=0;applyFilters();break;case 'skill-page':state.ui.skillsPage=Math.max(0,(state.ui.skillsPage||0)+Number(id));saveState();render();break;case 'codex-page':state.ui.codexPage=Math.max(0,(state.ui.codexPage||0)+Number(id));saveState();render();break;case 'catalog-detail':catalogDetail(id);break;
 case 'start-loop':startLoop();break;case 'stop-loop':stopLoop('手動停止');break;case 'clear-loop-log':state.loop.logs=[];saveState();render();break;
 case 'battle-skill':heroTurn(state.battle,id,false);render();break;case 'battle-defend':battleDefend();break;case 'battle-auto':toggleBattleAuto();break;case 'confirm-retreat':confirmModal('探索から撤退','報酬を得ずに探索を中断します。','retreat-battle','撤退する');break;case 'retreat-battle':closeModal();clearTimers();state.battle=null;state.screen='explore';saveState();render();break;
 case 'battle-return':clearTimers();state.battle=null;state.screen='home';saveState();render();break;case 'battle-again':startBattle(state.battle.regionId,state.battle.boss);break;
 case 'test-bgm':playBgm('home');toast('拠点BGMを再生中');break;case 'test-se':playSfx('rare');toast('SEを再生しました');break;
 default:break;
 }}
function chooseHeroForInventory(){modal('装備対象を選択',`<div class="hero-grid">${Object.values(state.heroes).map(h=>`<button class="hero-card ${state.ui.selectedHero===h.id?'selected':''}" data-act="select-inventory-hero" data-id="${h.id}">${heroCard(h).replace(/<article[^>]*>|<\/article>/g,'')}</button>`).join('')}</div>`)}

function applyFilters(){for(const key of ['inventoryFilter','inventoryType','inventoryRarity','inventoryTag','inventoryMinLevel','inventoryMaxLevel','inventorySort','skillsFilter','skillsTag']){const el=$(`[data-bind="${key}"]`);if(el)state.ui[key]=el.value}state.ui.inventoryPage=0;state.ui.skillsPage=0;saveState();render()}

document.addEventListener('click',e=>{const el=e.target.closest('[data-act]');if(!el)return;handleAction(el.dataset.act,el)});
document.addEventListener('change',e=>{const t=e.target;if(t.dataset.selectItem){const s=new Set(state.ui.inventorySelected||[]);t.checked?s.add(t.dataset.selectItem):s.delete(t.dataset.selectItem);setSelected([...s]);saveState();return}if(t.dataset.selectPageToggle){const view=inventoryView(),p=clamp(state.ui.inventoryPage||0,0,Math.max(0,Math.ceil(view.length/INVENTORY_PAGE_SIZE)-1)),ids=view.slice(p*INVENTORY_PAGE_SIZE,p*INVENTORY_PAGE_SIZE+INVENTORY_PAGE_SIZE).map(i=>i.uid),s=new Set(state.ui.inventorySelected||[]);ids.forEach(uid=>t.checked?s.add(uid):s.delete(uid));setSelected([...s]);saveState();render();return}if(t.dataset.bind){const key=t.dataset.bind;if(key==='loopRegion')state.loop.regionId=t.value;else if(key==='loopTarget')state.loop.target=clamp(+t.value||1,1,9999);else if(key==='loopStopHp')state.loop.stopHp=clamp(+t.value||0,0,100);else if(key==='loopStopMp')state.loop.stopMp=clamp(+t.value||0,0,100);else if(key==='loopStopXp')state.loop.stopXp=Math.max(0,+t.value||0);else if(key==='loopStopItem')state.loop.stopItem=t.value;else if(key==='loopMaterialCount')state.loop.stopMaterialCount=Math.max(0,+t.value||0);else if(key==='loopMaterial')state.loop.stopMaterial=t.value;else state.ui[key]=t.value;saveState();if(['loopRegion','loopTarget'].includes(key))render()}if(t.dataset.bindCheck){const v=t.checked,k=t.dataset.bindCheck;if(k==='loopBoss')state.loop.boss=v;else if(k==='loopUnlimited')state.loop.unlimited=v;else if(k==='loopRare')state.loop.stopRare=v;else if(k==='loopDeath')state.loop.stopDeath=v;else if(k==='loopFull')state.loop.stopFull=v;else if(['bulkExcludeEquipped','bulkExcludeLocked','bulkExcludeFavorite','bulkExcludeUnique'].includes(k))state.ui[k]=v;else if(k==='setBgm'){state.settings.bgm=v;setVolumes()}else if(k==='setSe')state.settings.se=v;saveState();if(['loopBoss','loopUnlimited','loopRare','loopDeath','loopFull','bulkExcludeEquipped','bulkExcludeLocked','bulkExcludeFavorite','bulkExcludeUnique','setBgm','setSe'].includes(k))render()}});
document.addEventListener('input',e=>{const t=e.target;if(t.dataset.bindRange){const v=clamp(+t.value/100,0,1);if(t.dataset.bindRange==='bgmVol'){state.settings.bgmVol=v;const lab=$('#bgm-vol-label');if(lab)lab.textContent=`${Math.round(v*100)}%`}else{state.settings.seVol=v;const lab=$('#se-vol-label');if(lab)lab.textContent=`${Math.round(v*100)}%`}setVolumes();saveState()}});
document.addEventListener('error',e=>{const img=e.target;if(img?.tagName==='IMG'){console.warn('[OMNIL asset missing]',img.src);img.classList.add('asset-missing');img.alt='素材未設定';}},true);
document.addEventListener('keydown',e=>{if(e.key==='Escape'){if($('#modal-root').innerHTML){closeModal();return}if(state.screen==='battle'&&state.battle&&!state.battle.result){toggleBattleAuto()}}});

state=loadState();
checkUnlocks();
render();

