export const __OMNIL_TEST__ = {
  getState:()=>state,
  setState:(v)=>{state=v},
  startBattle,
  runSimulation,
  grantRewards,
  checkUnlocks,
  getHeroStats,
  partyPower,
  saveState,
  resetState,
  render,
  startLoop,
  stopLoop,
  inventoryView,
  executeBulk,
  addDroppedItem,
  MAX_INVENTORY,
};
